def get_console():
    """Safe console access that works everywhere"""
    try:
        from rich.console import Console
        return Console()
    except ImportError:
        class FallbackConsole:
            def print(self, *args, **kwargs):
                print(*args, **kwargs)
        return FallbackConsole()

# Global console instance
console = get_console()

def _extract_slash_command(text: str) -> str | None:
    """Extracts a slash command from the beginning of the text."""
    import re
    match = re.match(r'^\s*(/\w+.*)', text, re.DOTALL)
    if match:
        return match.group(1).strip()
        return None
    
    import json
    import re
    
    def _extract_tool_calls_from_response(response: str) -> dict | None:
        """
        Extracts the first valid tool call JSON object from a model's response.
        Handles cases where the model might output multiple concatenated JSONs.
        """
        # Regex to find all JSON objects in the response
        json_objects = re.findall(r'\{[^}]*\}', response)
    
        for json_str in json_objects:
            try:
                parsed_json = json.loads(json_str)
                if isinstance(parsed_json, dict) and \
                   parsed_json.get("type") == "tool_call" and \
                   "name" in parsed_json and \
                   "args" in parsed_json:
                    return parsed_json
            except json.JSONDecodeError:
                continue
        return None
    
def _extract_one_line_json_ENHANCED(raw: str, obj_type: str = None) -> Optional[dict]:
    """
    Enhanced tool call extraction that handles more formats and provides
    better debugging information. Now includes format translation for Python-style calls.
    """
    _console = get_console()

    # DEBUG: Show what we're searching for
    if obj_type == "tool_call":
        _console.print(f"[dim yellow]DEBUG: Searching for tool call in response[/dim yellow]")

        # Check if response contains any tool-like patterns
        tool_indicators = [
            "tool_call", "function_call", "execute", "run_tool",
            "file_read", "file_write", "file_search", "bash_execute",
            '{"type":', '{"tool":', '{"name":', '{"function":',
            "I'll read", "I'll search", "Let me read", "Let me search"
        ]

        found_indicators = [ind for ind in tool_indicators if ind.lower() in raw.lower()]
        if found_indicators:
            _console.print(f"[dim cyan]Found tool indicators: {found_indicators}[/dim cyan]")

        # TRY FORMAT TRANSLATOR FIRST for Python-style function calls
        try:
            translator = FormatTranslator()
            translated = translator.translate(raw)
            if translated:
                info = translator.get_translation_info(raw)
                _console.print(f"[green]✓ Format translator succeeded ({info['detected_format']}, confidence: {info['confidence']})[/green]")
                _console.print(f"[dim cyan]Translated: {json.dumps(translated, indent=2)}[/dim cyan]")
                return translated
        except Exception as e:
            _console.print(f"[dim red]Format translator error: {e}[/dim red]")

    # ========== PATTERN 1: Clean JSON Lines ==========
    for ln in raw.splitlines():
        ln = ln.strip()
        # Remove markdown formatting
        ln = re.sub(r'^```(json|python|javascript)?', '', ln)  # Remove code fence prefix (```json, etc)
        ln = re.sub(r'```$', '', ln)  # Remove code fence suffix
        ln = re.sub(r'^[\s\*\-•›]+', '', ln)  # Remove bullets
        ln = ln.strip()

        if ln.startswith("{") and ln.endswith("}"):
            try:
                j = json.loads(ln)

                # OpenCode format: {"type":"tool_call","name":"...","args":{}}
                if obj_type == "tool_call" and j.get("type") == "tool_call":
                    _console.print(f"[green]✓ Found OpenCode format tool call[/green]")
                    return j

                # Gemma-tools format: {"tool":"...","args":{}}
                if obj_type == "tool_call" and "tool" in j and "args" in j:
                    _console.print(f"[green]✓ Found Gemma-tools format[/green]")
                    return {
                        "type": "tool_call",
                        "name": j["tool"],
                        "args": j.get("args", {})
                    }

                # Function call format: {"function":"...","parameters":{}}
                if obj_type == "tool_call" and "function" in j and "parameters" in j:
                    _console.print(f"[green]✓ Found function call format[/green]")
                    return {
                        "type": "tool_call",
                        "name": j["function"],
                        "args": j.get("parameters", {})
                    }

                # Direct tool format: {"file_read":{"path":"..."}}
                for tool in ["file_read", "file_write", "file_search", "bash_execute", "directory_list"]:
                    if tool in j:
                        _console.print(f"[green]✓ Found direct tool format: {tool}[/green]")
                        return {
                            "type": "tool_call",
                            "name": tool,
                            "args": j[tool] if isinstance(j[tool], dict) else {"path": j[tool]}
                        }

            except json.JSONDecodeError as e:
                if obj_type == "tool_call":
                    _console.print(f"[dim red]JSON parse error: {e} for line: {ln[:100]}...[/dim red]")

    # ========== PATTERN 2: Embedded JSON with Regex ==========
    patterns = [
        # Standard formats
        r'\{"type"\s*:\s*"tool_call"[^}]*\}',
        r'\{"tool"\s*:\s*"([^"]+)"[^}]*\}',
        r'\{"function"\s*:\s*"([^"]+)"[^}]*\}',
        r'\{"name"\s*:\s*"([^"]+)"[^}]*"parameters"\s*:\s*\{[^}]*\}\s*\}',
        # Markdown code blocks
        r'```json\s*(\{[^`]*\})\s*```',
        r'```\s*(\{[^`]*\})\s*```',
        # Natural language patterns
        r'(?:I\'ll|Let me|Going to|Will)\s+(\w+)\s+(?:the\s+)?file\s+"([^"]+)"',
    ]

    for pattern in patterns:
        matches = re.findall(pattern, raw, re.IGNORECASE | re.DOTALL)
        for match in matches:
            try:
                if isinstance(match, tuple):
                    # Natural language pattern
                    action, target = match
                    if action.lower() in ['read', 'open', 'check', 'examine']:
                        _console.print(f"[green]✓ Found natural language: {action} {target}[/green]")
                        return {
                            "type": "tool_call",
                            "name": "file_read",
                            "args": {"file_path": target}
                        }
                    elif action.lower() in ['search', 'find', 'look']:
                        _console.print(f"[green]✓ Found natural language: {action} {target}[/green]")
                        return {
                            "type": "tool_call",
                            "name": "file_search",
                            "args": {"pattern": target, "path": "."}
                        }
                else:
                    # JSON pattern
                    j = json.loads(match)
                    if isinstance(j, dict) and "type" in j and j["type"] == "tool_call":
                        _console.print(f"[green]✓ Found tool call via regex[/green]")
                        return j
            except:
                continue

    # ========== PATTERN 3: Fallback Detection ==========
    if obj_type == "tool_call":
        # Look for common tool request phrases
        tool_phrases = {
            "file_read": ["read the file", "open the file", "show the file", "display the file"],
            "file_search": ["search for", "find the file", "look for", "locate"],
            "file_write": ["write to", "create a file", "save to"],
            "bash_execute": ["run the command", "execute", "run bash"],
            "directory_list": ["list files", "show files", "ls", "dir"]
        }

        raw_lower = raw.lower()
        for tool_name, phrases in tool_phrases.items():
            for phrase in phrases:
                if phrase in raw_lower:
                    # Extract potential file name or command
                    file_pattern = r'["\']([^"\']+)["\']'
                    file_matches = re.findall(file_pattern, raw)
                    if file_matches:
                        _console.print(f"[yellow]⚠ Detected '{phrase}' with target: {file_matches[0]}[/yellow]")
                        _console.print(f"[yellow]Creating fallback tool call for {tool_name}[/yellow]")

                        # Build args based on specific tool requirements
                        if tool_name == "file_search":
                            args = {"pattern": file_matches[0], "path": "."}
                        elif tool_name == "file_read":
                            args = {"file_path": file_matches[0]}
                        elif tool_name == "file_write":
                            args = {"file_path": file_matches[0], "content": ""}
                        elif tool_name == "bash_execute":
                            args = {"command": file_matches[0]}
                        elif tool_name == "directory_list":
                            args = {"path": file_matches[0] if file_matches[0] != "files" else "."}
                        else:
                            args = {"path": file_matches[0]}

                        return {
                            "type": "tool_call",
                            "name": tool_name,
                            "args": args
                        }

    # No tool call found
    if obj_type == "tool_call":
        _console.print(f"[red]✗ No tool call found in response[/red]")
        _console.print(f"[dim]Response preview: {raw[:200]}...[/dim]")

    return None

async def _safe_execute_tool(interactive_self, name: str, args: dict):
    """Execute tool with orchestrator validation/confirmation gates"""
    _console = get_console()
    try:
        # PARAMETER NORMALIZATION - Map common variations to expected parameter names
        # This handles models using different parameter names than what tools expect

        # File operations - all use file_path
        if name in ["file_read", "read_text", "file_write", "file_edit", "file_delete", "file_create", "file_fill"]:
            if "path" in args and "file_path" not in args:
                args["file_path"] = args.pop("path")
            elif "filename" in args and "file_path" not in args:
                args["file_path"] = args.pop("filename")
            elif "file" in args and "file_path" not in args:
                args["file_path"] = args.pop("file")
            elif "filepath" in args and "file_path" not in args:
                args["file_path"] = args.pop("filepath")

        # file_search - expects pattern and path
        if name == "file_search":
            if "file_name" in args and "pattern" not in args:
                args["pattern"] = args.pop("file_name")
            elif "filename" in args and "pattern" not in args:
                args["pattern"] = args.pop("filename")
            elif "name" in args and "pattern" not in args:
                args["pattern"] = args.pop("name")
            if "directory" in args and "path" not in args:
                args["path"] = args.pop("directory")
            elif "dir" in args and "path" not in args:
                args["path"] = args.pop("dir")

            # Safeguard against empty search pattern
            if 'pattern' not in args or not args.get('pattern'):
                return {"success": False, "output": "", "error": "Search failed: You must specify a pattern to search for."}

        # grep_search - expects pattern, path, file_pattern
        if name == "grep_search":
            if "text" in args and "pattern" not in args:
                args["pattern"] = args.pop("text")
            elif "search" in args and "pattern" not in args:
                args["pattern"] = args.pop("search")
            if "directory" in args and "path" not in args:
                args["path"] = args.pop("directory")
            elif "dir" in args and "path" not in args:
                args["path"] = args.pop("dir")

        # directory_list - expects path
        if name == "directory_list":
            if "directory" in args and "path" not in args:
                args["path"] = args.pop("directory")
            elif "dir" in args and "path" not in args:
                args["path"] = args.pop("dir")

        # Execute with enhanced args
        # - show live progress
        from rich.spinner import Spinner
        from rich.live import Live
        import asyncio
        import time

        # Create live display with spinner (transient so it clears for confirmations)
        spinner = Spinner("dots", text=f"[cyan]Executing {name}...[/cyan]")
        start_time = time.time()

        with Live(spinner, console=_console, refresh_per_second=10, transient=True) as live:
            # Execute tool
            res = await interactive_self.tool_manager.execute_tool(name, **args)
            elapsed = time.time() - start_time

            # Update with result + show output size (stop being transient to show result)
            output_size = len(str(getattr(res, "output", "")))
            if getattr(res, "success", True):
                live.transient = False  # Keep result visible
                live.update(f"[green]✓ {name}[/green] [dim]({elapsed:.2f}s, {output_size} chars)[/dim]")
            else:
                error = getattr(res, "error", "Unknown error")
                live.transient = False  # Keep error visible
                live.update(f"[red]✗ {name} failed[/red] [dim]({elapsed:.2f}s)[/dim]")

        return {"success": getattr(res, "success", True), "output": getattr(res, "output", "") or "", "error": getattr(res, "error", None)}
    except Exception as e:
        _console.print(f"[red]Error executing tool {name}: {e}[/red]")
        import traceback
        _console.print(f"[dim]{traceback.format_exc()}[/dim]")
        return {"success": False, "output": "", "error": str(e)}

async def _execute_auto_chain(interactive_self, initial_tool: str, initial_args: Dict) -> List[ToolResult]:
    """Safely execute auto-chain with proper error handling"""
    _console = get_console()
    try:
        # VALIDATE INPUTS FIRST
        if not isinstance(initial_args, dict):
            _console.print(f"[red]Auto-chain failed: invalid args type {type(initial_args)}[/red]")
            return []

        file_path = initial_args.get('file_path')
        if not file_path or not isinstance(file_path, str):
            _console.print(f"[red]Auto-chain failed: invalid file_path {file_path}[/red]")
            return []

        # SAFE AUTO-CHAIN: file_read → file_search first
        if initial_tool == 'file_read':
            from pathlib import Path

            # Extract just the filename for search
            filename = Path(file_path).name

            # Normalize filename - strip leading dot (common model error)
            if filename.startswith('.') and len(filename) > 1:
                filename = filename.lstrip('.')
                _console.print(f"[dim cyan]Normalized filename by removing leading dot[/dim cyan]")

            # Execute file_search safely
            search_result = await _safe_execute_tool(
                interactive_self,
                'file_search',
                {'pattern': filename,
                'path': '.',  # Current directory only
                'case_sensitive': False  # Case-insensitive to find README.md when looking for readme.txt
            })
            
            if search_result.get('success') and search_result.get('output'):
                # Parse search results to find exact file
                lines = search_result.get('output').split('\n')
                if lines and 'No matching files' not in search_result.get('output'):
                    # Use first result found
                    actual_path = lines[0].strip()
                    _console.print(f"[green]Auto-chain found: {filename} → {actual_path}[/green]")

                    # Execute the original file_read with corrected path
                    read_result = await _safe_execute_tool(
                        interactive_self,
                        'file_read',
                        {'file_path': actual_path}
                    )
                    # Only return if read was successful
                    if read_result.get('success'):
                        return [search_result, read_result]
                    else:
                        _console.print(f"[yellow]Auto-chain: File read failed for {actual_path}[/yellow]")
                        return []  # Let normal tool execution handle the error
                else:
                    _console.print(f"[yellow]Auto-chain: No files found for {filename}[/yellow]")
                    return []  # Let normal tool execution handle the error
            else:
                _console.print(f"[yellow]Auto-chain search failed for {filename}[/yellow]")
                return []  # Let normal tool execution handle the error

        return []
        
    except Exception as e:
        _console.print(f"[red]Auto-chain error: {str(e)}[/red]")
        return []

async def _call_model_with_tool_result(interactive_self, tool_payload_str: str, user_input: str, turn_num: int = 1, max_turns: int = 5):
    """Call model with tool result formatted as an assistant message

    Format the tool result as a system message with clear framing so the model
    understands it's a tool output, not user input.
    """
    # Calculate remaining turns
    remaining_turns = max_turns - turn_num

    # Format structured exit hint based on remaining turns
    if remaining_turns == 0:
        # FINAL TURN - must answer now
        exit_hint = """
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
⚠️  FINAL TURN - No more tool calls allowed
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
You MUST output now based on the information you have from tool use and the user input.
"""
        next_action = "REFER TO INITIAL REQUEST -> PARSE-TOOL-RESULT-> RE-ACT."
    elif remaining_turns == 1:
        # One turn remaining - encourage answer if possible
        exit_hint = f"""
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
💡 Tool calls remaining: {remaining_turns}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
"""
        next_action = """CONSIDER:
1. Has the initial user request been fully satisfied by the tool result?
2. If YES, respond to the user in plain English.
3. If NO, and further tool use is necessary, make another tool call.
4. If NO, and further tool use is NOT necessary, respond to the user in plain English, explaining why the request cannot be fully satisfied."""
    else:
        # Multiple turns remaining
        exit_hint = f"""
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
💡 Tool calls remaining: {remaining_turns}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
"""
        next_action = """CONSIDER:
1. Has the initial user request been fully satisfied by the tool result?
2. If YES, respond to the user in plain English.
3. If NO, and further tool use is necessary, make another tool call.
4. If NO, and further tool use is NOT necessary, respond to the user in plain English, explaining why the request cannot be fully satisfied."""

    enhanced_prompt = f"""{user_input}

[TOOL RESULT]:
{tool_payload_str}
{exit_hint}

{next_action}"""

    # Use the existing enhanced_generate method with system prompt
    if interactive_self.quality_manager:
        resp = await interactive_self.quality_manager.enhanced_generate(
            prompt=enhanced_prompt,
            system_prompt=interactive_self._get_dynamic_system_prompt()
        )
    else:
        # Fallback to direct ollama_client call if quality_manager not available
        resp = await interactive_self.ollama_client.generate(
            prompt=enhanced_prompt,
            system_prompt=interactive_self._get_dynamic_system_prompt()
        )
    return resp

def _estimate_tokens(text: str) -> int:
    """Rough token estimation (4 chars ≈ 1 token)"""
    return len(text) // 4

def _format_tool_result_as_text(tool_name: str, tool_args: dict, result: dict, step_num: int = None) -> str:
    """
    Format tool results as PLAIN TEXT for model readability.

    Returns clear, human-readable text showing:
    - Tool name and arguments
    - Success/failure status
    - Actual output content
    - Next action hints
    """
    output = str(result.get('output', ''))
    error = result.get('error', '')
    success = result.get('success', False)

    # Build step header
    if step_num:
        header = f"{step_num}. {tool_name}("
    else:
        header = f"{tool_name}("

    # Add arguments
    arg_strs = [f'{k}="{v}"' for k, v in tool_args.items()]
    header += ", ".join(arg_strs) + ")"

    lines = [header]

    # Status line
    if success:
        lines.append("   STATUS: ✓ Success")
    else:
        lines.append(f"   STATUS: ✗ Failed")
        lines.append(f"   ERROR: {error}")
        return "\n".join(lines)

    # Tool-specific output formatting
    if tool_name == 'file_read':
        lines.append(f"   FILE CONTENTS ({len(output)} chars):")
        # Indent file contents
        for line in output.split('\n'):
            lines.append(f"   {line}")

    elif tool_name == 'file_search':
        files = [f.strip() for f in output.strip().split('\n') if f.strip()]
        lines.append(f"   FOUND: {len(files)} file(s)")
        for f in files[:5]:  # Show first 5
            lines.append(f"   - {f}")
        if len(files) > 5:
            lines.append(f"   ... and {len(files) - 5} more")

    elif tool_name == 'directory_list':
        items = [i.strip() for i in output.strip().split('\n') if i.strip()]
        lines.append(f"   ITEMS: {len(items)} files/directories")
        for item in items[:10]:
            lines.append(f"   - {item}")
        if len(items) > 10:
            lines.append(f"   ... and {len(items) - 10} more")

    elif tool_name == 'bash_execute':
        lines.append(f"   COMMAND OUTPUT:")
        for line in output.split('\n')[:20]:  # First 20 lines
            lines.append(f"   {line}")
        if output.count('\n') > 20:
            remaining_lines = output.count('\n') - 20
            lines.append(f"   ... ({remaining_lines} more lines)")

    elif tool_name == 'web_search':
        lines.append(f"   SEARCH RESULTS:")
        lines.append(f"   {output[:500]}")  # First 500 chars
        if len(output) > 500:
            lines.append(f"   ... (truncated)")

    else:
        # Generic output
        lines.append(f"   OUTPUT:")
        preview = output[:300]
        for line in preview.split('\n'):
            lines.append(f"   {line}")
        if len(output) > 300:
            lines.append(f"   ... (truncated from {len(output)} chars)")

    return "\n".join(lines)

def _format_tool_result_for_model(tool_name: str, tool_args: dict, result: dict) -> dict:
    """
    Format tool results with clear structure and next-action hints.
    Makes results easier for models to parse and act on.

    NOTE: This returns a dict for backward compatibility. Use _format_tool_result_as_text()
    for plain text formatting that models can actually read.
    """
    output = str(result.get('output', ''))
    error = result.get('error', '')
    success = result.get('success', False)
    formatted_result = result.copy()

    # Handle FAILURES first with tool-specific guidance
    if not success:
        error_lower = error.lower()

        if tool_name == 'file_read':
            if 'not found' in error_lower or 'no such file' in error_lower:
                formatted_result['summary'] = f"✗ File not found: {tool_args.get('file_path')}"
                formatted_result['next_action_hint'] = "Use file_search to locate the file, or directory_list to see available files in current directory"
            elif 'permission denied' in error_lower or 'access denied' in error_lower:
                formatted_result['summary'] = "✗ Permission denied"
                formatted_result['next_action_hint'] = "File exists but cannot be read. Check file permissions or try a different file."
            elif 'outside' in error_lower or 'workdir' in error_lower:
                formatted_result['summary'] = "✗ Path is outside allowed working directory"
                formatted_result['next_action_hint'] = "Use change_directory to navigate, or request files within the current working directory"
            else:
                formatted_result['summary'] = f"✗ Failed to read file: {error}"
                formatted_result['next_action_hint'] = "Check file path and try again"

        elif tool_name == 'file_write':
            if 'permission denied' in error_lower:
                formatted_result['summary'] = "✗ Cannot write file - permission denied"
                formatted_result['next_action_hint'] = "Check write permissions for target directory"
            elif 'directory' in error_lower and 'not found' in error_lower:
                formatted_result['summary'] = "✗ Parent directory does not exist"
                formatted_result['next_action_hint'] = "Create parent directories first or use file_create with create_dirs option"
            else:
                formatted_result['summary'] = f"✗ Failed to write file: {error}"
                formatted_result['next_action_hint'] = "Verify file path and permissions"

        elif tool_name == 'file_search':
            if 'no files found' in error_lower or 'not found' in error_lower:
                formatted_result['summary'] = f"✗ No files match pattern: {tool_args.get('pattern')}"
                formatted_result['next_action_hint'] = "Try broader pattern (e.g., '*.txt' instead of specific name) or use directory_list to explore"
            else:
                formatted_result['summary'] = f"✗ Search failed: {error}"
                formatted_result['next_action_hint'] = "Check search pattern syntax and try again"

        elif tool_name == 'grep_search':
            if 'not found' in error_lower:
                formatted_result['summary'] = f"✗ No matches found for pattern: {tool_args.get('pattern')}"
                formatted_result['next_action_hint'] = "Pattern exists but no matches. Try different pattern or check file contents with file_read"
            else:
                formatted_result['summary'] = f"✗ Search failed: {error}"
                formatted_result['next_action_hint'] = "Check regex pattern syntax"

        elif tool_name == 'bash_execute':
            if 'not found' in error_lower or 'command not found' in error_lower:
                formatted_result['summary'] = f"✗ Command not found: {tool_args.get('command')}"
                formatted_result['next_action_hint'] = "Command doesn't exist or is not in PATH. Check command name or use system_info to verify available commands"
            elif 'permission denied' in error_lower:
                formatted_result['summary'] = "✗ Command permission denied"
                formatted_result['next_action_hint'] = "Command requires elevated permissions or is not allowed"
            elif 'timeout' in error_lower:
                formatted_result['summary'] = "✗ Command timed out"
                formatted_result['next_action_hint'] = "Command took too long. Try with shorter timeout or optimize command"
            else:
                formatted_result['summary'] = f"✗ Command failed: {error}"
                formatted_result['next_action_hint'] = "Check command syntax and arguments"

        elif tool_name == 'directory_list':
            if 'not found' in error_lower or 'no such' in error_lower:
                formatted_result['summary'] = f"✗ Directory not found: {tool_args.get('path')}"
                formatted_result['next_action_hint'] = "Use directory_list on parent directory or change_directory to navigate"
            else:
                formatted_result['summary'] = f"✗ Failed to list directory: {error}"
                formatted_result['next_action_hint'] = "Check directory path"

        elif tool_name == 'change_directory':
            if 'not found' in error_lower or 'no such' in error_lower:
                formatted_result['summary'] = f"✗ Directory does not exist: {tool_args.get('path')}"
                formatted_result['next_action_hint'] = "Use directory_list to see available directories"
            else:
                formatted_result['summary'] = f"✗ Cannot change directory: {error}"
                formatted_result['next_action_hint'] = "Check directory path and permissions"

        elif tool_name == 'git_operations':
            if 'not a git repository' in error_lower:
                formatted_result['summary'] = "✗ Not a git repository"
                formatted_result['next_action_hint'] = "Run git_operations with operation='init' first, or navigate to a git repository"
            elif 'not found' in error_lower:
                formatted_result['summary'] = "✗ Git not installed or command not found"
                formatted_result['next_action_hint'] = "Git is not available on this system"
            else:
                formatted_result['summary'] = f"✗ Git operation failed: {error}"
                formatted_result['next_action_hint'] = "Check git command syntax and repository state"

        elif tool_name == 'web_search':
            if 'no results' in error_lower:
                formatted_result['summary'] = f"✗ No search results for: {tool_args.get('query')}"
                formatted_result['next_action_hint'] = "Try different search terms or broader query"
            else:
                formatted_result['summary'] = f"✗ Web search failed: {error}"
                formatted_result['next_action_hint'] = "Check network connection or try again later"

        elif tool_name == 'web_fetch':
            if 'connection' in error_lower or 'network' in error_lower:
                formatted_result['summary'] = f"✗ Network error: {error}"
                formatted_result['next_action_hint'] = "Check network connection or URL validity"
            elif '404' in error or 'not found' in error_lower:
                formatted_result['summary'] = "✗ URL not found (404)"
                formatted_result['next_action_hint'] = "Verify URL is correct and accessible"
            else:
                formatted_result['summary'] = f"✗ Failed to fetch URL: {error}"
                formatted_result['next_action_hint'] = "Check URL and try again"

        else:
            # Generic failure
            formatted_result['summary'] = f"✗ {tool_name} failed: {error}"
            formatted_result['next_action_hint'] = "Check arguments and try again, or try alternative approach"

        return formatted_result

    # Handle SUCCESS cases
    if tool_name == 'file_search':
        lines = [line.strip() for line in output.strip().split('\n') if line.strip()]
        count = len(lines)
        if count > 0:
            formatted_result['summary'] = f"✓ Found {count} file(s)"
            formatted_result['files'] = lines
            formatted_result['next_action_hint'] = f"Use file_read with file_path=\"{lines[0]}\" to view contents"
        else:
            formatted_result['summary'] = "✗ No files found matching pattern"
            formatted_result['next_action_hint'] = "Try different pattern or check directory"

    elif tool_name == 'file_read':
        char_count = len(output)
        line_count = output.count('\n') + 1
        formatted_result['summary'] = f"✓ Read file ({line_count} lines, {char_count} chars)"
        formatted_result['content'] = output
        formatted_result['next_action_hint'] = "Analyze content or answer user's question"

    elif tool_name == 'directory_list':
        lines = [line.strip() for line in output.strip().split('\n') if line.strip()]
        count = len(lines)
        formatted_result['summary'] = f"✓ Listed {count} items"
        formatted_result['items'] = lines
        formatted_result['next_action_hint'] = "Use file_read to examine files or directory_list for subdirectories"

    elif tool_name == 'bash_execute':
        formatted_result['summary'] = "✓ Command executed"
        formatted_result['output'] = output
        formatted_result['next_action_hint'] = "Analyze command output or run additional commands if needed"

    elif tool_name == 'change_directory':
        formatted_result['summary'] = f"✓ Changed to directory: {tool_args.get('path')}"
        formatted_result['next_action_hint'] = "Use directory_list to see contents of new directory"

    elif tool_name == 'git_operations':
        formatted_result['summary'] = f"✓ Git {tool_args.get('operation')} completed"
        formatted_result['next_action_hint'] = "Check git status or continue with other git operations"

    elif tool_name == 'web_search':
        formatted_result['summary'] = f"✓ Found search results"
        formatted_result['next_action_hint'] = "Analyze results or use web_fetch to get specific URLs"

    elif tool_name == 'web_fetch':
        formatted_result['summary'] = f"✓ Fetched URL content"
        formatted_result['next_action_hint'] = "Analyze fetched content"

    else:
        # Generic success formatting
        formatted_result['summary'] = f"✓ {tool_name} completed"
        formatted_result['next_action_hint'] = "Analyze result or make another tool call if needed"

    return formatted_result

class _NullMVCO:
    """Null object pattern for MVCO when disabled"""
    def predict_next_state(self, *args, **kwargs):
        return {"confidence": 0.0, "recommended_model": None}
    def add_interaction(self, *args, **kwargs):
        return None
    def bootstrap_with_models(self, *args, **kwargs):
        return None
    def shutdown(self, *args, **kwargs):
        return None

@dataclass
class ConversationEntry:
    """Single conversation entry"""
    timestamp: str
    user_input: str
    assistant_response: str
    tool_calls: List[Dict] = None
    metadata: Dict = None
    
    def to_dict(self) -> Dict:
        return asdict(self)
    
    @classmethod
    def from_dict(cls, data: Dict) -> 'ConversationEntry':
        # Ensure backward compatibility for sessions without metadata field
        if 'metadata' not in data:
            data['metadata'] = None
        if 'tool_calls' not in data:
            data['tool_calls'] = None
        return cls(**data)

def _flag(obj, name: str, default: bool = False) -> bool:
    """Safely access boolean flags from dataclass config objects"""
    return bool(getattr(obj, name, default)) if obj is not None else bool(default)

class ConversationHistory:
    """Manages session-based conversation history"""

    def __init__(self, config: Config):
        self.config = config
        self.entries: List[ConversationEntry] = []
        self.session_summary: str = ""

        # Conversation state tracking for gradual resource allocation
        from opencode.conversation_state import ConversationState
        self.resource_state = ConversationState()

        # Session-based storage (project-aware)
        # Scope logs/sessions by active version if provided
        import os as _os
        _ver = _os.getenv('OPENCODE_VERSION', '').strip()
        if _ver and (Path('versions') / _ver / 'logs').exists():
            self.logs_dir = Path('versions') / _ver / 'logs'
        else:
            self.logs_dir = Path('logs')
        self.debug_dir = self.logs_dir / 'debug'
        self.exports_dir = self.logs_dir / 'exports' / 'conversation-exports'

        # Default sessions dir under logs/, but prefer active project directory if set
        current_project = project_store.get_current_project()
        if current_project:
            base_sessions = project_store.get_project_path(current_project.id) / 'sessions'
        else:
            base_sessions = self.logs_dir / 'sessions'
        self.sessions_dir = base_sessions

        # Create directories if they don't exist
        self.sessions_dir.mkdir(parents=True, exist_ok=True)
        self.debug_dir.mkdir(parents=True, exist_ok=True)
        self.exports_dir.mkdir(parents=True, exist_ok=True)

        # Session management
        self.current_session_id = None
        self.session_metadata = {}
        self.model_name = config.model.name.replace(':', '-').replace('/', '-')  # Safe filename
        self.model_dir = self.sessions_dir / self.model_name
        self.model_dir.mkdir(exist_ok=True)

        # Session index file
        self.session_index_file = self.sessions_dir / 'session-index.json'

        # Debug timing mode
        self.debug_timing = False

        self.load_or_create_session()
    
    def add_entry(self, user_input: str, assistant_response: str, tool_calls: List[Dict] = None, metadata: Dict = None):
        """Add a new conversation entry to current session"""
        entry = ConversationEntry(
            timestamp=datetime.now().isoformat(),
            user_input=user_input,
            assistant_response=assistant_response,
            tool_calls=tool_calls or []
        )

        # Add routing metadata if provided
        if metadata:
            entry.metadata = metadata

        self.entries.append(entry)

        # Update conversation state for gradual resource allocation
        try:
            complexity_score = metadata.get('complexity_score', 0.0) if metadata else 0.0
            used_tools = bool(tool_calls and len(tool_calls) > 0)
            tool_count = len(tool_calls) if tool_calls else 0
            self.resource_state.update_for_turn(
                complexity_score=complexity_score,
                used_tools=used_tools,
                tool_count=tool_count
            )
        except Exception:
            # Silently fail - resource state is optimization, not critical
            pass

        # Update rolling session summary periodically
        try:
            self._update_session_summary()
        except Exception:
            pass

        # Also log to project store for future RAG integration
        try:
            # Log user input
            project_store.log_conversation(
                role="user",
                content=user_input,
                metadata={
                    "session_id": self.current_session_id,
                    "model": self.model_name,
                    "timestamp": entry.timestamp
                }
            )

            # Log assistant response
            project_store.log_conversation(
                role="assistant",
                content=assistant_response,
                metadata={
                    "session_id": self.current_session_id,
                    "model": self.model_name,
                    "timestamp": entry.timestamp,
                    "tool_calls": tool_calls,
                    "routing_metadata": metadata
                }
            )
        except Exception as e:
            # Don't fail conversation on logging errors
            console.print(f"[dim yellow]Warning: Could not log to project: {e}[/dim yellow]")

        # Update session metadata
        self.session_metadata['last_updated'] = datetime.now().isoformat()
        self.session_metadata['entry_count'] = len(self.entries)
        if self.session_summary:
            self.session_metadata['summary'] = self.session_summary

        # Limit history size
        if len(self.entries) > self.config.history.max_entries:
            self.entries = self.entries[-self.config.history.max_entries:]

        if self.config.history.save_to_file:
            self.save_current_session()
    
    def load_or_create_session(self):
        """Load existing session or create new one"""
        # Respect resume behavior
        if not self.config.history.save_to_file or not getattr(self.config.history, 'resume_last_session', True):
            self.create_new_session()
            return

        # Check for current session symlink
        current_session_link = self.model_dir / 'current-session.json'

        if current_session_link.exists() and current_session_link.is_symlink():
            # Load existing current session
            try:
                session_file = current_session_link.resolve()
                if session_file.exists():
                    self.load_session_file(session_file)
                    return
            except Exception as e:
                console.print(f"[yellow]Warning: Could not load current session: {e}[/yellow]")

        # Create new session if no current session exists
        self.create_new_session()
    
    def create_new_session(self):
        """Create a new conversation session"""
        timestamp = datetime.now().strftime('%Y-%m-%d_%H-%M-%S')

        # Find next session number
        existing_sessions = list(self.model_dir.glob('session-*.json'))
        session_numbers = []
        for session_file in existing_sessions:
            try:
                num = int(session_file.stem.split('-')[1].split('_')[0])
                session_numbers.append(num)
            except (ValueError, IndexError):
                continue

        next_session_num = max(session_numbers, default=0) + 1
        self.current_session_id = f"session-{next_session_num:03d}"

        # Create session metadata
        self.session_metadata = {
            'session_id': self.current_session_id,
            'model_name': self.config.model.name,
            'model_config': {
                'temperature': self.config.model.temperature,
                'max_tokens': self.config.model.max_tokens,
                'base_url': self.config.model.base_url
            },
            'created': datetime.now().isoformat(),
            'last_updated': datetime.now().isoformat(),
            'entry_count': 0
        }

        self.entries = []
        self.save_current_session()
        self.update_session_index()

        console.print(f"[dim]Started new session: {self.current_session_id}[/dim]")

    def save_current_session(self):
        """Save current session to file"""
        if not self.current_session_id:
            return

        try:
            timestamp = datetime.now().strftime('%Y-%m-%d_%H-%M-%S')
            session_filename = f"{self.current_session_id}_{timestamp}.json"
            session_file = self.model_dir / session_filename

            # Prepare session data
            session_data = {
                **self.session_metadata,
                'entries': [entry.to_dict() for entry in self.entries]
            }

            # Save session file
            with open(session_file, 'w') as f:
                json.dump(session_data, f, indent=2)

            # Update current session symlink
            current_session_link = self.model_dir / 'current-session.json'
            if current_session_link.exists():
                current_session_link.unlink()
            current_session_link.symlink_to(session_filename)

        except Exception as e:
            console.print(f"[yellow]Warning: Could not save session: {e}[/yellow]")

    def load_session_file(self, session_file: Path):
        """Load session from specific file"""
        try:
            with open(session_file, 'r') as f:
                session_data = json.load(f)

            self.session_metadata = {
                k: v for k, v in session_data.items()
                if k != 'entries'
            }
            self.current_session_id = session_data.get('session_id')

            entries_data = session_data.get('entries', [])
            self.entries = [ConversationEntry.from_dict(entry) for entry in entries_data]

        except Exception as e:
            console.print(f"[yellow]Warning: Could not load session file: {e}[/yellow]")
            self.create_new_session()

    def update_session_index(self):
        """Update the global session index"""
        try:
            # Load existing index
            session_index = {}
            if self.session_index_file.exists():
                with open(self.session_index_file, 'r') as f:
                    session_index = json.load(f)

            # Update index
            if self.model_name not in session_index:
                session_index[self.model_name] = []

            # Add current session if not already present
            session_info = {
                'session_id': self.current_session_id,
                'created': self.session_metadata['created'],
                'last_updated': self.session_metadata['last_updated'],
                'entry_count': self.session_metadata['entry_count']
            }

            # Remove any existing entry for this session and add updated one
            session_index[self.model_name] = [
                s for s in session_index[self.model_name]
                if s['session_id'] != self.current_session_id
            ]
            session_index[self.model_name].append(session_info)

            # Save updated index
            with open(self.session_index_file, 'w') as f:
                json.dump(session_index, f, indent=2)

        except Exception as e:
            console.print(f"[yellow]Warning: Could not update session index: {e}[/yellow]")
    
    def get_context(self, max_entries: int = 5, include_summary: bool = True, token_budget: int | None = None) -> str:
        """Get recent conversation context.

        Includes user inputs, tool results, AND assistant responses
        to maintain conversation continuity and prevent repetition.
        """
        if not self.entries:
            return ""

        recent_entries = self.entries[-max_entries:]
        lines = []

        # Prepend session summary when available and requested
        if include_summary and self.session_summary:
            lines.append(f"Summary: {self.session_summary}")

        for entry in recent_entries:
            # Avoid leaking tool-only placeholder lines into model context
            meta = getattr(entry, 'metadata', None)
            is_tool_only = bool(meta and isinstance(meta, dict) and meta.get('tool_only'))
            if is_tool_only:
                # Omit tool-only turn content to avoid nudging model toward tools
                lines.append("User: [previous tool request omitted]")
            else:
                lines.append(f"User: {entry.user_input}")

            # CRITICAL: Include tool results to prevent amnesia
            # Model needs to remember what tools returned
            if entry.tool_calls and len(entry.tool_calls) > 0:
                tool_memory = []
                for tool_call in entry.tool_calls:
                    # Handle different tool_call structures (orchestrator vs legacy)
                    tool_name = tool_call.get('tool') or tool_call.get('tool_name', 'unknown')
                    tool_output = tool_call.get('output', '')
                    tool_success = tool_call.get('success', True)

                    # For failed tools, show error instead
                    if not tool_success and tool_call.get('error'):
                        tool_output = f"ERROR: {tool_call.get('error')}"

                    # Truncate long results to save context
                    if isinstance(tool_output, str) and len(tool_output) > 150:
                        tool_output = tool_output[:150] + "..."

                    # Include success status for clarity
                    status = "✓" if tool_success else "✗"
                    tool_memory.append(f"{status} {tool_name}: {tool_output}")

                if tool_memory:
                    lines.append("  [Previous tool results: " + " | ".join(tool_memory) + "]")

            # CRITICAL: Include assistant response for conversation continuity
            # Truncate to save tokens but maintain context of what was already explained
            if entry.assistant_response:
                response_text = entry.assistant_response
                # Truncate long responses to ~300 chars to save context
                if len(response_text) > 300:
                    response_text = response_text[:300] + "..."
                lines.append(f"Assistant: {response_text}")

        context_text = "\n".join(lines)
        # Approximate token fitting by word count when budget provided
        if token_budget and token_budget > 0:
            # if too long, drop oldest lines until roughly within budget
            words = context_text.split()
            if len(words) > token_budget:
                # remove from the top (older entries)
                while lines and len(" ".join("\n".join(lines).split())) > token_budget:
                    # drop first non-summary line
                    if lines and (include_summary and lines[0].startswith("Summary:")):
                        # keep summary; drop next
                        if len(lines) > 1:
                            lines.pop(1)
                        else:
                            break
                    else:
                        lines.pop(0)
                context_text = "\n".join(lines)
        return context_text

    def _update_session_summary(self, max_items: int = 8, max_words: int = 12) -> None:
        """Build a lightweight session summary from recent user inputs.

        Heuristic-only (no model call): take up to `max_items` recent user
        messages and compress each to `max_words` words.
        """
        if not self.entries:
            self.session_summary = ""
            return

        user_texts: List[str] = []
        for e in self.entries:
            txt = (e.user_input or '').strip()
            if txt:
                user_texts.append(txt)

        if not user_texts:
            self.session_summary = ""
            return

        recent = user_texts[-max_items:]
        compressed: List[str] = []
        for t in recent:
            words = t.split()
            if len(words) > max_words:
                comp = " ".join(words[:max_words]) + "…"
            else:
                comp = t
            compressed.append(comp)

        # Join as brief bullets in a single line to keep context small
        self.session_summary = " | ".join(compressed)

    def search_conversations(self, query: str, max_results: int = 5) -> List[ConversationEntry]:
        """Search through conversation history for relevant entries"""
        if not self.entries or not query.strip():
            return []

        query_lower = query.lower()
        scored_entries = []

        for entry in self.entries:
            score = 0

            # Search in user input
            if query_lower in entry.user_input.lower():
                score += 2

            # Search in assistant response
            if query_lower in entry.assistant_response.lower():
                score += 1

            # Search for individual words
            query_words = query_lower.split()
            for word in query_words:
                if len(word) > 2:  # Skip very short words
                    if word in entry.user_input.lower():
                        score += 0.5
                    if word in entry.assistant_response.lower():
                        score += 0.3

            if score > 0:
                scored_entries.append((score, entry))

        # Sort by score (highest first) and return top results
        scored_entries.sort(key=lambda x: x[0], reverse=True)
        return [entry for _, entry in scored_entries[:max_results]]

    def find_list_entries(self) -> List[ConversationEntry]:
        """Find entries that contain lists (for recall queries about counts)"""
        list_patterns = [
            r'\d+\.\s+',  # Numbered lists
            r'[-*]\s+',   # Bullet lists
            r'Here are \d+ ',  # "Here are N items"
            r'List of \d+ ',   # "List of N items"
        ]

        list_entries = []
        for entry in self.entries:
            for pattern in list_patterns:
                if re.search(pattern, entry.assistant_response):
                    list_entries.append(entry)
                    break

        return list_entries[-5:]  # Return last 5 list entries

    def get_last_items_count(self) -> Optional[int]:
        """Get count of items from the most recent list"""
        list_entries = self.find_list_entries()
        if not list_entries:
            return None

        last_entry = list_entries[-1]

        # Try to count numbered items
        numbered_items = re.findall(r'^\d+\.\s+', last_entry.assistant_response, re.MULTILINE)
        if numbered_items:
            return len(numbered_items)

        # Try to count bullet items
        bullet_items = re.findall(r'^[-*]\s+', last_entry.assistant_response, re.MULTILINE)
        if bullet_items:
            return len(bullet_items)

        # Look for explicit count mentions
        count_match = re.search(r'(?:Here are|List of)\s+(\d+)', last_entry.assistant_response)
        if count_match:
            return int(count_match.group(1))

        return None
    
    def clear(self):
        """Clear current session history"""
        self.entries = []
        self.session_metadata['entry_count'] = 0
        self.session_metadata['last_updated'] = datetime.now().isoformat()

        if self.config.history.save_to_file:
            self.save_current_session()

    def list_sessions(self) -> Dict:
        """List all sessions by model"""
        try:
            if self.session_index_file.exists():
                with open(self.session_index_file, 'r') as f:
                    return json.load(f)
            return {}
        except Exception as e:
            console.print(f"[yellow]Warning: Could not load session index: {e}[/yellow]")
            return {}

    def load_session(self, session_id: str) -> bool:
        """Load a specific session by ID"""
        # Find session file
        session_files = list(self.model_dir.glob(f"{session_id}_*.json"))
        if not session_files:
            return False

        # Load the most recent file for this session
        session_file = max(session_files, key=lambda f: f.stat().st_mtime)
        self.load_session_file(session_file)

        # Update current session symlink
        try:
            current_session_link = self.model_dir / 'current-session.json'
            if current_session_link.exists():
                current_session_link.unlink()
            current_session_link.symlink_to(session_file.name)
        except Exception as e:
            console.print(f"[yellow]Warning: Could not update current session link: {e}[/yellow]")

        return True

    def export_session(self, session_id: str = None) -> Optional[Path]:
        """Export session to exports folder"""
        if session_id is None:
            session_id = self.current_session_id

        if not session_id:
            return None

        try:
            # Find session file
            session_files = list(self.model_dir.glob(f"{session_id}_*.json"))
            if not session_files:
                return None

            session_file = max(session_files, key=lambda f: f.stat().st_mtime)

            # Create export filename
            export_filename = f"{self.model_name}_{session_id}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
            export_path = self.exports_dir / export_filename

            # Copy session file to exports
            import shutil
            shutil.copy2(session_file, export_path)

            return export_path

        except Exception as e:
            console.print(f"[yellow]Warning: Could not export session: {e}[/yellow]")
            return None

import logging

logger = logging.getLogger(__name__)

class CommandCompleter(Completer):
    """Command completer for OpenCode interactive mode"""

    def __init__(self, ollama_client: OllamaClient):
        self.ollama_client = ollama_client
        self._cached_models = []  # Will be populated asynchronously
        self.commands = {
            '/help': 'Show help information',
            '/quit': 'Exit the program',
            '/clear': 'Clear conversation history',
            '/history': 'Show conversation history',
            '/tools': 'Show available tools or toggle tool prompt injection (enable/disable)',
            '/model': 'Switch model or list available models',
            '/prompt': 'View/enable/disable system prompt or set temporary custom prompt',
            '/compact': 'Toggle compact mode',
            '/settings': 'Manage application settings',
            '/mode': 'Set resource and generation mode',
            '/debug': 'Toggle debug timing mode (on/off)',
            '/doctor': 'Run system diagnostics and validation',
            '/project': 'Manage projects and storage',
            '/quality': 'Manage quality recovery system',
            '/agentic': 'Manage agentic project workflows',
            '/version': 'Manage versions (list/<label>|save/end/new)',
            '/coding': 'Create and manage coding experiments',
            '/mcp': 'MCP server status and control'
        }

    def get_completions(self, document, complete_event):
        word = document.get_word_before_cursor()
        text = document.text_before_cursor

        # Handle /history command with sub-option suggestions
        if text.startswith('/history '):
            history_options = ['list', 'sessions', 'load', 'export', 'clear', 'new']
            for option in history_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /settings command with sub-option suggestions
        elif text.startswith('/settings '):
            # Check if we're completing a value for tools.enable or tools.disable
            if 'tools.enable ' in text or 'tools.disable ' in text:
                # Suggest tool names
                tool_names = [
                    'file_read', 'file_write', 'file_edit', 'file_search',
                    'file_copy', 'file_move', 'file_delete', 'file_create',
                    'directory_list', 'change_directory',
                    'grep_search', 'code_analyze', 'package_check',
                    'bash_execute', 'process_manage', 'git_operations',
                    'web_search', 'web_fetch', 'system_info', 'resource_request'
                ]
                for tool_name in tool_names:
                    if tool_name.startswith(word):
                        yield Completion(tool_name, start_position=-len(word))
            else:
                # Show settings options
                settings_options = [
                    'model', 'interface', 'history', 'tools', 'system', 'runtime', 'mcp',
                    'model.auto-config', 'model.current', 'model.temperature', 'model.max_tokens', 'model.profiles',
                    'interface.compact_mode', 'interface.syntax_highlighting', 'interface.theme', 'interface.auto_save', 'interface.auto_model_selection', 'interface.default_mode', 'interface.auto_suggest_tools',
                    'history.max_entries', 'history.save_to_file', 'history.auto_clear', 'history.file_path', 'history.resume_last_session',
                    'tools.enabled', 'tools.timeout', 'tools.bash', 'tools.list', 'tools.show',
                    'tools.enable', 'tools.disable', 'tools.auto_retry', 'tools.max_retries', 'tools.cache_results', 'tools.cache_ttl',
                    'tools.confirmation_level', 'tools.auto_chain', 'tools.clear_cache',
                    'runtime.resources', 'runtime.auto_detect', 'runtime.gpu_enabled', 'runtime.fallback_model',
                    'mcp.enabled', 'mcp.auto_start', 'mcp.mode',
                    'system.save', 'system.reset', 'system.export', 'system.import'
                ]

                for option in settings_options:
                    if option.startswith(word):
                        yield Completion(option, start_position=-len(word))

        # Handle /debug command with on/off suggestions
        elif text.startswith('/debug '):
            debug_options = ['on', 'off']
            for option in debug_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /prompt command with enable/disable suggestions
        elif text.startswith('/prompt '):
            # Check if we're completing after 'enable' or 'disable'
            if text.endswith('enable ') or text.endswith('disable '):
                prompt_options = ['save']
            else:
                prompt_options = ['enable', 'disable', 'reset', 'load']
            for option in prompt_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /tools command with prompt subcommand suggestions
        elif text.startswith('/tools '):
            if text.startswith('/tools prompt '):
                # After 'prompt', suggest enable/disable
                if text.endswith('enable ') or text.endswith('disable '):
                    tools_options = ['save']
                else:
                    tools_options = ['enable', 'disable']
                for option in tools_options:
                    if option.startswith(word):
                        yield Completion(option, start_position=-len(word))
            else:
                # First level: suggest modes, 'prompt', and actual tool names
                special_options = ['prompt', '--model', '--verbose']

                # Get all available tool names
                try:
                    tool_names = self.interactive_mode.tool_manager.get_all_tool_names() if hasattr(self, 'interactive_mode') else []
                except:
                    tool_names = []

                # Combine special options and tool names
                all_options = special_options + tool_names

                for option in all_options:
                    if option.startswith(word):
                        yield Completion(option, start_position=-len(word))

        # Handle /mode command with mode suggestions
        elif text.startswith('/mode '):
            mode_options = ['fast', 'auto', 'think', 'smart', 'thinktime']
            for option in mode_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /doctor command with sub-options
        elif text.startswith('/doctor '):
            doctor_options = ['hardware', 'models', 'config', 'storage', 'mcp', 'full']
            for option in doctor_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /project command with sub-options
        elif text.startswith('/project '):
            project_options = ['list', 'new', 'select', 'current', 'export', 'archive', 'info']
            for option in project_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /model command with model suggestions
        elif text.startswith('/model '):
            # Always show 'refresh' option first, then cached models
            options = ['refresh'] + (self._cached_models if self._cached_models else [])

            for option in options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /quality command with sub-options
        elif text.startswith('/quality '):
            quality_options = ['status', 'mode', 'optimize', 'enable', 'disable']
            for option in quality_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        elif text.startswith('/version'):
            # Smart completion: suggest subcommands and available version labels with markers
            version_options = ['list', 'save', 'end', 'new']
            # Determine the argument after '/version '
            arg = text[len('/version'):].lstrip()
            tokens = arg.split()
            if not tokens:
                # First arg: show subcommands only (no labels here)
                for option in version_options:
                    if option.startswith(word):
                        yield Completion(option, start_position=-len(word))
            else:
                # If saving, suggest labels only
                if tokens[0] == 'save':
                    try:
                        if VersionManager:
                            vm = VersionManager(base_dir='versions')
                            for it in vm.list_versions_with_status():
                                lb = it['label']
                                if lb.startswith(word):
                                    yield Completion(lb, start_position=-len(word))
                    except Exception:
                        pass
                elif tokens[0] == 'list':
                    # Suggest available version labels after '/version list '
                    try:
                        if VersionManager:
                            vm = VersionManager(base_dir='versions')
                            items = vm.list_versions_with_status()
                            stable = vm.get_stable() or ''
                            import os as _os
                            cur_env = _os.getenv('OPENCODE_VERSION', '').strip()
                            current = cur_env or stable
                            for it in items:
                                lb = it['label']
                                if not it['complete']:
                                    continue
                                markers = []
                                if lb == stable:
                                    markers.append('STABLE')
                                if lb == current:
                                    markers.append('CURRENT')
                                disp = lb + ("  <" + " ".join(markers) + ">" if markers else "")
                                if lb.startswith(word):
                                    yield Completion(lb, start_position=-len(word), display=disp)
                    except Exception:
                        pass
                elif tokens[0] in ('end', 'list', 'new'):
                    # No extra suggestions needed
                    pass

        # Handle /agentic command with sub-options
        elif text.startswith('/agentic '):
            agentic_options = ['status', 'create', 'list']
            for option in agentic_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle /tools command with flags and tool name lookup
        elif text.startswith('/tools '):
            # If typing a flag, suggest flags
            if word.startswith('-'):
                flag_options = ['--model', '--verbose', '-v']
                for option in flag_options:
                    if option.startswith(word):
                        yield Completion(option, start_position=-len(word))
            else:
                # Otherwise suggest available tool names for quick lookup
                # Note: tool_manager won't be available in completer context,
                # so we provide a static list of common tools
                tool_names = [
                    'file_read', 'file_write', 'file_edit', 'file_search',
                    'file_copy', 'file_move', 'file_delete', 'file_create',
                    'directory_list', 'change_directory',
                    'grep_search', 'code_analyze', 'package_check',
                    'bash_execute', 'process_manage', 'git_operations',
                    'web_search', 'web_fetch', 'system_info', 'resource_request'
                ]
                for tool_name in tool_names:
                    if tool_name.startswith(word):
                        yield Completion(tool_name, start_position=-len(word))

        # Handle /coding command with sub-options
        elif text.startswith('/coding '):
            coding_options = ['new', 'list', 'where', 'open', 'status', 'gen', 'run']
            for option in coding_options:
                if option.startswith(word):
                    yield Completion(option, start_position=-len(word))

        # Handle base commands starting with /
        elif text.startswith('/'):
            for command in self.commands:
                if command.startswith(text):
                    yield Completion(
                        command,
                        start_position=-len(text),
                        display_meta=self.commands[command]
                    )

    async def update_model_cache(self):
        """Update cached model list asynchronously - includes Ollama, llama.cpp GGUF, and LM Studio models"""
        models = []

        # Get Ollama models
        try:
            ollama_models = await self.ollama_client.list_models()
            models.extend([f"{m} (ollama)" for m in ollama_models])
        except:
            pass

        # Get llama.cpp GGUF models
        try:
            from pathlib import Path
            models_dir = Path("/home/commander/Desktop/BackupOpencode/models")
            if models_dir.exists():
                gguf_files = [f.stem for f in sorted(models_dir.glob("*.gguf"))]
                models.extend([f"{m} (gguf)" for m in gguf_files])
        except:
            pass

        # Get LM Studio models
        try:
            if self.lmstudio_client:
                async with self.lmstudio_client as client:
                    lms_models = await client.list_models()
                    models.extend([f"{m} (lmstudio)" for m in lms_models])
        except:
            pass

        self._cached_models = models

class InteractiveMode:
    """Interactive mode for OpenCode"""

    def _as_dict(self, obj, default=None):
        """Defensive helper to ensure object behaves like a dict"""
        if hasattr(obj, 'get') and callable(getattr(obj, 'get')):
            return obj
        return default or {}

    def _keyboard_listener(self):
        """Background thread to listen for Ctrl+O during streaming"""
        try:
            old_settings = termios.tcgetattr(sys.stdin)
            try:
                tty.setcbreak(sys.stdin.fileno())
                while not self._stop_keyboard_listener:
                    if sys.stdin in select.select([sys.stdin], [], [], 0.1)[0]:
                        ch = sys.stdin.read(1)
                        # Ctrl+O is ASCII 15 (0x0F)
                        if ord(ch) == 15:
                            self._show_thinking = not self._show_thinking
                            status = "ON" if self._show_thinking else "OFF"
                            console.print(f"\n[cyan]💭 Thinking display: {status} (Ctrl+O)[/cyan]")
            finally:
                termios.tcsetattr(sys.stdin, termios.TCSADRAIN, old_settings)
        except Exception as e:
            console.print(f"[dim yellow]Keyboard listener error: {e}[/dim yellow]")

    def _start_keyboard_listener(self):
        """Start keyboard listener thread for Ctrl+O"""
        if self._keyboard_thread is None or not self._keyboard_thread.is_alive():
            self._stop_keyboard_listener = False
            self._keyboard_thread = threading.Thread(target=self._keyboard_listener, daemon=True)
            self._keyboard_thread.start()
            console.print("[dim]Keyboard listener started - Press Ctrl+O to toggle thinking[/dim]")

    def _stop_keyboard_listener_thread(self):
        """Stop keyboard listener thread"""
        self._stop_keyboard_listener = True
        if self._keyboard_thread:
            self._keyboard_thread.join(timeout=0.5)

    def _filter_thinking(self, response: Any) -> str:
        """Safely filter thinking patterns with type checking"""
        _console = get_console()
        try:
            # ENSURE response is string
            if not isinstance(response, str):
                if response is None:
                    return ""
                return str(response)

            # Safe regex filtering
            thinking_patterns = [
                r"^[\s\u2800]*[Tt]hink(ing)?[\s\u2800]*[:]?[\s\u2800]*$",
                r"^[\s\u2800]*[Ll]et me [\s\u2800]*(think|reason)[\s\u2800]*[:]?[\s\u2800]*$",
                r"^[\s\u2800]*[Hh]mm[^a-zA-Z]*$"
            ]

            filtered = response
            for pattern in thinking_patterns:
                try:
                    filtered = re.sub(pattern, '', filtered, flags=re.IGNORECASE)
                except Exception as e:
                    # If regex fails, continue with original text
                    _console.print(f"[yellow]Regex filter warning: {e}[/yellow]")
                    continue

            return filtered.strip()

        except Exception as e:
            _console.print(f"[red]Filter thinking error: {e}[/red]")
            return str(response) if response else ""

    def get_active_client(self):
        """Get the active model client based on current backend selection"""
        if self.active_backend == "lmstudio" and self.lmstudio_client:
            console.print(f"[dim green]→ Using LM Studio client (backend: {self.active_backend})[/dim green]")
            return self.lmstudio_client
        elif self.active_backend == "llamacpp" and self.llamacpp_client:
            console.print(f"[dim green]→ Using llama.cpp client (backend: {self.active_backend})[/dim green]")
            return self.llamacpp_client
        console.print(f"[dim yellow]→ Using Ollama client (backend: {self.active_backend})[/dim yellow]")
        return self.ollama_client

    def _get_dynamic_system_prompt(self, include_tools: bool = False) -> str:
        """Get system prompt with dynamic values injected

        Args:
            include_tools: If True, inject tool descriptions (only for tool_use tasks)
        """
        # Check if system prompt is disabled
        if not self.system_prompt_enabled:
            return ""  # Return empty prompt when disabled

        # Use temporary custom prompt if set, otherwise use config prompt
        prompt = self.temp_system_prompt if self.temp_system_prompt else self.config.system_prompt

        # DEBUG: Log system prompt status
        if not prompt:
            console.print(f"[red bold]CRITICAL: config.system_prompt is empty/None![/red bold]")
            console.print(f"[red]Config object: {self.config}[/red]")
            console.print(f"[red]Config has system_prompt attr: {hasattr(self.config, 'system_prompt')}[/red]")
            console.print(f"[red]system_prompt type: {type(prompt)}[/red]")
            # Fallback to basic prompt
            prompt = "You are a helpful coding assistant. Use tools when needed."
        else:
            # Store initial size for debugging
            initial_size = len(prompt)

        # Inject current working directory
        working_dir = str(self.tool_manager.working_dir)
        prompt = prompt.replace('{working_dir}', working_dir)

        # Inject available tools dynamically ONLY if requested (for tool_use tasks)
        # AND if tools_prompt_enabled is True (controlled by /tools command)
        if include_tools and getattr(self, 'tools_prompt_enabled', True):
            # Use LangChain's auto-generated schemas if available (more robust)
            if hasattr(self, 'lc_adapter') and self.lc_adapter:
                try:
                    import json
                    tool_schemas = self.lc_adapter.get_tool_schemas_for_model()
                    tool_list = json.dumps(tool_schemas, indent=2)
                except Exception as e:
                    # Fallback to original tool descriptions
                    tool_list = self.tool_manager.get_tool_descriptions()
            else:
                tool_list = self.tool_manager.get_tool_descriptions()

            prompt = prompt.replace('{available_tools}', tool_list)
        else:
            # Remove the placeholder to avoid confusion
            prompt = prompt.replace('{available_tools}', '')

        # Log tool count and final size for debugging
        if hasattr(self, 'history') and self.history.debug_timing:
            tool_count = len(self.tool_manager.get_available_tools())
            final_size = len(prompt.split())
            console.print(f"[dim cyan]DEBUG: System prompt = {final_size} words ({len(prompt)} chars, {tool_count} tools) [base: {initial_size} chars][/dim cyan]")

        return prompt

    def __init__(self, ollama_client: OllamaClient, tool_manager: ToolManager, config: Config):
        self.ollama_client = ollama_client
        self.tool_manager = tool_manager
        self.config = config

        # Initialize llama.cpp client for GGUF models
        try:
            from .llamacpp_client import LlamaCppClient
            self.llamacpp_client = LlamaCppClient(config.model)
            self.llamacpp_client.interactive_mode = True
        except Exception as e:
            console.print(f"[yellow]Warning: Could not initialize llama.cpp client: {e}[/yellow]")
            self.llamacpp_client = None

        # Initialize LM Studio client
        try:
            from .lmstudio_client import LMStudioClient
            self.lmstudio_client = LMStudioClient(config.model)
            self.lmstudio_client.interactive_mode = True
        except Exception as e:
            console.print(f"[yellow]Warning: Could not initialize LM Studio client: {e}[/yellow]")
            self.lmstudio_client = None

        # Default to Ollama backend; surface local GGUF availability without auto-switching
        self.active_backend = "ollama"
        self._detected_local_gguf = None
        if self.llamacpp_client:
            console.print(f"[yellow]DEBUG: Checking for GGUF model: {config.model.name}[/yellow]")
            model_path = self.llamacpp_client._find_gguf_model(config.model.name)
            console.print(f"[yellow]DEBUG: Found GGUF path: {model_path}[/yellow]")
            if model_path:
                self.llamacpp_client.current_model_path = model_path
                self._detected_local_gguf = model_path
                console.print("[dim cyan]✓ Local GGUF detected (use /model to switch to llama.cpp backend)[/dim cyan]")
            else:
                console.print(f"[yellow]DEBUG: No GGUF found, remaining on Ollama[/yellow]")
        else:
            console.print(f"[yellow]DEBUG: llama.cpp client unavailable, remaining on Ollama[/yellow]")

        # DEBUG: Log system prompt at initialization
        console.print(f"[cyan]DEBUG: InteractiveMode.__init__()[/cyan]")
        console.print(f"[cyan]  config.system_prompt exists: {hasattr(config, 'system_prompt')}[/cyan]")
        if hasattr(config, 'system_prompt'):
            sp_len = len(config.system_prompt) if config.system_prompt else 0
            console.print(f"[cyan]  config.system_prompt length: {sp_len}[/cyan]")
            if sp_len > 0:
                console.print(f"[cyan]  First 100 chars: {config.system_prompt[:100]}[/cyan]")

        # Versioned overlay manager (non-destructive testing)
        self.version_manager = None
        self._overlay_active_banner_shown = False
        try:
            if VersionManager:
                self.version_manager = VersionManager(base_dir='versions')
        except Exception:
            self.version_manager = None
        self.history = ConversationHistory(config)
        self.session_manager = IntelligentSessionManager(config)
        self.tool_orchestrator = AdvancedToolOrchestrator(tool_manager, config)

        # Pass history reference to ollama_client for debug timing access
        self.ollama_client.interactive_mode = True
        self.ollama_client.history = self.history
        # self.pre_rag_optimizer = None
        self.quant_manager = DynamicQuantizationManager()

        # System prompt control - load from config if available
        self.system_prompt_enabled = getattr(config, 'system_prompt_enabled', True)  # Gate for system prompt usage
        self.temp_system_prompt = None  # Temporary session-only custom prompt

        # Tool prompt injection control - load from config if available
        self.tools_prompt_enabled = getattr(config, 'tools_prompt_enabled', True)  # Gate for tool injection in system prompt

        # LangChain adapter - provides battle-tested tool parsing and schema generation
        try:
            from .langchain_adapter_simple import SimpleLangChainAdapter
            self.lc_adapter = SimpleLangChainAdapter(tool_manager)
            console.print("[dim]✓ LangChain-style tool adapter initialized[/dim]")
        except Exception as e:
            console.print(f"[yellow]⚠ LangChain adapter failed to initialize: {e}[/yellow]")
            self.lc_adapter = None

        # MVCO orchestrator (always define the attribute)
        opt = getattr(self.config, "optimization", None)
        if opt and getattr(opt, "use_mvco_router", False):
            self.mvco_orchestrator = MVCO()
        else:
            self.mvco_orchestrator = _NullMVCO()
        # alias for legacy references
        self.mvco = self.mvco_orchestrator

        # Bootstrap MVCO with available models for better initial recommendations (only if enabled)
        if opt and getattr(opt, "use_mvco_router", False):
            try:
                available_models = self.quant_manager.get_available_models()
                if available_models:
                    self.mvco_orchestrator.bootstrap_with_models(available_models)
            except Exception as e:
                pass  # Silent fallback if bootstrap fails
        self.completer = CommandCompleter(ollama_client)

        # Thinking display state (toggle with /thinking command or Ctrl+O during streaming)
        self._show_thinking = False  # Show model's internal reasoning
        self._token_counter = 0  # Token counter for current generation
        self._start_time = 0  # Start time for elapsed tracking
        self._keyboard_thread = None  # Thread for Ctrl+O detection
        self._stop_keyboard_listener = False  # Flag to stop keyboard thread

        self.session = PromptSession(
            history=FileHistory('.opencode_input_history'),
            completer=self.completer,
            complete_style=CompleteStyle.COLUMN,
            refresh_interval=1.0
        )

        # Initialize Quality Recovery System if available
        qr_cfg = getattr(config, 'quality_recovery', None)
        if QUALITY_SYSTEM_AVAILABLE and _flag(qr_cfg, 'enabled', True):
            try:
                self.quality_manager = integrate_quality_system(self)
                # Override generation method with quality-enhanced version
                self._original_generate_with_resources = self._generate_with_resources
                self._generate_with_resources = self.quality_manager.enhanced_generate
                console.print("[dim]✨ Quality Recovery System: ACTIVE[/dim]")
            except Exception as e:
                console.print(f"[dim yellow]Quality system initialization failed: {e}[/dim yellow]")
                self.quality_manager = None
        else:
            self.quality_manager = None

        # If an active experiment exists for the current version, default tool cwd to it
        try:
            import os as _os, json as _json
            ver = _os.getenv('OPENCODE_VERSION', '').strip() or 'default'
            state_path = Path('versions') / ver / 'experiments' / '.state.json'
            if state_path.exists():
                data = _json.loads(state_path.read_text())
                exp = data.get('active_experiment')
                if exp and Path(exp).is_dir():
                    self.tool_manager.working_dir = Path(exp).resolve()
                    console.print(f"[dim]Active experiment detected; tool cwd set to: {self.tool_manager.working_dir}[/dim]")
            else:
                # Fallback: Use experiments directory directly if it exists
                exp_dir = Path('experiments')
                if exp_dir.exists() and exp_dir.is_dir():
                    # Find most recent experiment
                    experiments = sorted([d for d in exp_dir.iterdir() if d.is_dir()], key=lambda x: x.stat().st_mtime, reverse=True)
                    if experiments:
                        self.tool_manager.working_dir = experiments[0].resolve()
                        console.print(f"[dim]Using most recent experiment: {self.tool_manager.working_dir}[/dim]")
        except Exception as e:
            console.print(f"[dim yellow]Could not set experiment directory: {e}[/dim yellow]")
            pass

        # Always show actual working directory for debugging
        console.print(f"[dim cyan]Tool working directory: {self.tool_manager.working_dir}[/dim cyan]")

        # Initialize policy provider early based on config
        try:
            if getattr(getattr(self.config, 'policy', None), 'enabled', True):
                provider_name = str(getattr(self.config.policy, 'provider', 'basic')).lower()
                self.policy_provider = AdaptivePolicyProvider() if provider_name in ('advanced', 'adaptive') else BasicPolicyProvider()
            else:
                self.policy_provider = None
        except Exception:
            self.policy_provider = None

        # Track Ctrl+C count for graceful vs forced exit
        self._interrupt_count = 0
        self._last_interrupt_time = 0

        # Register signal handlers for graceful shutdown
        self._setup_signal_handlers()

        # Initialize MCP integration
        self.mcp_integration: Optional[MCPIntegration] = None
        self._mcp_enabled = (
            hasattr(config, 'mcp') and
            getattr(config.mcp, 'enabled', False)
        )

    def _setup_signal_handlers(self):
        """Setup signal handlers for graceful shutdown"""
        def sigint_handler(signum, frame):
            """Handle SIGINT (Ctrl+C) - allow model interruption, force exit on double press"""
            import time
            current_time = time.time()

            # Reset counter if more than 2 seconds since last interrupt
            if current_time - self._last_interrupt_time > 2.0:
                self._interrupt_count = 0

            self._interrupt_count += 1
            self._last_interrupt_time = current_time

            if self._interrupt_count == 1:
                # First Ctrl+C: let KeyboardInterrupt propagate normally (interrupt model)
                console.print("\n[yellow]Interrupted (press Ctrl+C again within 2s to force exit)[/yellow]")
                raise KeyboardInterrupt()
            else:
                # Second Ctrl+C: force exit with cleanup
                console.print("\n[yellow]Force exit - cleaning up...[/yellow]")
                self._cleanup_and_exit()

        def sigterm_handler(signum, frame):
            """Handle SIGTERM (kill command) - always cleanup and exit"""
            console.print("\n[yellow]Received SIGTERM, cleaning up...[/yellow]")
            self._cleanup_and_exit()

        # Register handlers
        signal.signal(signal.SIGINT, sigint_handler)  # Ctrl+C
        signal.signal(signal.SIGTERM, sigterm_handler)  # kill command

    def _cleanup_and_exit(self):
        """Cleanup resources and exit (called from signal handlers)"""
        try:
            if hasattr(self, 'ollama_client') and self.ollama_client:
                console.print(f"[dim]Unloading model {self.config.model.name}...[/dim]")
                # Try sync cleanup - don't create new event loop (causes conflicts)
                try:
                    # Call sync version if available, otherwise skip
                    if hasattr(self.ollama_client, 'unload_model_sync'):
                        self.ollama_client.unload_model_sync()
                        console.print("[dim]Model unloaded[/dim]")
                    else:
                        # Can't properly await in signal handler - just skip
                        console.print("[dim]Model cleanup skipped (async conflict)[/dim]")
                except Exception as cleanup_err:
                    console.print(f"[dim]Model cleanup error: {cleanup_err}[/dim]")
        except Exception as e:
            console.print(f"[dim]Could not unload model: {e}[/dim]")

        # Exit cleanly
        console.print("[dim]Goodbye![/dim]")

        # Force stop all async tasks and exit immediately
        import sys
        import os
        # Use os._exit() instead of sys.exit() to bypass cleanup and stop immediately
        # This prevents zombie processes where signal handlers don't fully stop execution
        os._exit(0)

