    async def export_session(self, session_id: str = None):
        """Export a session to the exports folder"""
        export_path = self.history.export_session(session_id)
        if export_path:
            console.print(f"[green]Session exported to: {export_path}[/green]")
        else:
            target = session_id or "current session"
            console.print(f"[red]Failed to export {target}[/red]")

    async def clear_session(self):
        """Clear current session after confirmation"""
        if not self.history.entries:
            console.print("[yellow]Current session is already empty[/yellow]")
            return

        # Create operation info for confirmation gate
        operation = OperationInfo(
            operation_name="Clear Session",
            description=f"Clear current session ({self.history.current_session_id})",
            risk_level=RiskLevel.MEDIUM,
            affected_items=[f"{len(self.history.entries)} conversation entries"],
            consequences=[
                "Current conversation history will be cleared",
                "Session analytics will be reset",
                "Context will be lost"
            ],
            reversible=False,
            backup_available=True,  # Session can be exported first
            estimated_time="< 5 seconds"
        )

        # Require confirmation
        if not confirmation_gate.require_confirmation(operation):
            console.print("[yellow]Session clear cancelled[/yellow]")
            return

        # Backup current session before clearing
        if hasattr(self, 'session_manager'):
            self.session_manager.backup_session_data()

        self.history.clear()
        console.print("[green]Session cleared[/green]")

    async def create_new_session(self):
        """Create a new conversation session"""
        old_session = self.history.current_session_id
        self.history.create_new_session()
        if old_session:
            console.print(f"[green]Created new session: {self.history.current_session_id}[/green]")
            console.print(f"[dim]Previous session: {old_session}[/dim]")
        else:
            console.print(f"[green]Created session: {self.history.current_session_id}[/green]")

    def show_tools(self, mode: str = 'list', tool_name: str = None):
        """Show available tools

        Args:
            mode: 'list' (brief), 'model' (what model sees), 'verbose' (full schemas), 'lookup' (specific tool)
            tool_name: Specific tool name for 'lookup' mode
        """
        if mode == 'lookup':
            # Show detailed info for specific tool
            if not tool_name:
                console.print("[yellow]Usage: /tools <tool_name>[/yellow]")
                return

            # Check if tool exists
            all_tools = self.tool_manager.get_all_tool_names()
            if tool_name not in all_tools:
                console.print(f"[red]✗ Tool '{tool_name}' not found[/red]")
                console.print(f"[dim]Available tools: {', '.join(all_tools[:10])}...[/dim]")
                return

            # Get tool schema
            schemas = self.tool_manager.get_tool_schemas()
            tool_schema = next((s for s in schemas if s.get('function', {}).get('name') == tool_name), None)

            if not tool_schema:
                console.print(f"[yellow]Schema not available for '{tool_name}'[/yellow]")
                return

            # Display detailed tool info
            func = tool_schema.get('function', {})
            enabled = self.tool_manager.is_tool_enabled(tool_name)
            status = "[green]ENABLED[/green]" if enabled else "[red]DISABLED[/red]"

            console.print(f"\n[cyan bold]Tool: {func.get('name')}[/cyan bold] {status}")
            console.print(f"\n[yellow]Description:[/yellow]")
            console.print(f"  {func.get('description', 'N/A')}")

            params = func.get('parameters', {}).get('properties', {})
            required = func.get('parameters', {}).get('required', [])

            if params:
                console.print(f"\n[yellow]Parameters:[/yellow]")
                for param_name, param_info in params.items():
                    req_badge = " [red bold](required)[/red bold]" if param_name in required else " [dim](optional)[/dim]"
                    param_type = param_info.get('type', 'any')
                    param_desc = param_info.get('description', 'N/A')
                    console.print(f"  [green]• {param_name}[/green] [{param_type}]{req_badge}")
                    console.print(f"    {param_desc}")

            # Show usage example
            console.print(f"\n[yellow]Usage Example:[/yellow]")
            example_args = ', '.join([f'"{p}": "value"' for p in list(params.keys())[:3]])
            console.print(f'  {{"type":"tool_call","name":"{tool_name}","args":{{{example_args}}}}}')

            # Show enable/disable command
            if enabled:
                console.print(f"\n[dim]To disable: /settings tools.disable {tool_name}[/dim]")
            else:
                console.print(f"\n[dim]To enable: /settings tools.enable {tool_name}[/dim]")

        elif mode == 'model':
            # Show exactly what the model sees in system prompt
            console.print("[cyan bold]Tools as seen by the model:[/cyan bold]\n")
            tool_section = self.tool_manager.get_tool_descriptions()
            console.print(Panel(tool_section, title="<AVAILABLE_TOOLS>", border_style="cyan"))

            # Show full system prompt if verbose
            console.print("\n[dim]This is injected into the system prompt at runtime.[/dim]")
            console.print(f"[dim]Total tools enabled: {len(self.tool_manager.get_available_tools())}[/dim]")

        elif mode == 'verbose':
            # Show detailed schemas - EXACTLY what model receives
            console.print("[cyan bold]Tool Schemas (EXACTLY what model receives):[/cyan bold]\n")

            # Use LangChain adapter if available (same source model uses)
            if hasattr(self, 'lc_adapter') and self.lc_adapter:
                schemas = self.lc_adapter.get_tool_schemas_for_model()
            else:
                # Fallback to tool_manager if adapter not available
                schemas = self.tool_manager.get_tool_schemas()
                # Convert from {"type": "function", "function": {...}} to just {...}
                schemas = [s.get('function', s) for s in schemas]

            for schema in schemas:
                console.print(f"[green]• {schema.get('name')}[/green]")
                console.print(f"  {schema.get('description')}")
                params = schema.get('parameters', {}).get('properties', {})
                required = schema.get('parameters', {}).get('required', [])
                if params:
                    console.print("  [yellow]Parameters:[/yellow]")
                    for param_name, param_info in params.items():
                        req = " [red](required)[/red]" if param_name in required else ""
                        console.print(f"    - {param_name}: {param_info.get('description', 'N/A')}{req}")
                console.print()

            console.print(f"[dim]Total: {len(schemas)} schemas (same as model receives)[/dim]")

        else:  # mode == 'list' (default)
            # Show brief list (same as model sees, but formatted nicely)
            console.print("[cyan bold]Available Tools:[/cyan bold]\n")
            tool_list = self.tool_manager.get_tool_descriptions()
            console.print(tool_list)
            console.print(f"\n[dim]Total: {len(self.tool_manager.get_available_tools())} tools enabled[/dim]")
            console.print("[dim]Use '/tools --model' to see model's view or '/tools --verbose' for full schemas[/dim]")

