    def auto_configure_model_by_size(self, model_name: str):
        """Auto-configure model settings based on size"""

        # Size detection patterns
        size_patterns = {
            'tiny': ['tiny', '1b', '1.1b'],           # < 2B params
            'small': ['2b', '3b'],                    # 2-4B params
            'medium': ['7b', '8b', '9b'],            # 5-10B params
            'large': ['13b', '15b', '20b', '30b'],   # 10-35B params
            'xlarge': ['70b', '120b']                # 35B+ params
        }

        # Detect model size
        model_lower = model_name.lower()
        detected_size = 'medium'  # default

        for size, patterns in size_patterns.items():
            if any(pattern in model_lower for pattern in patterns):
                detected_size = size
                break

        # Size-based configurations
        configs = {
            'tiny': {
                'temperature': 0.4,
                'max_tokens': 1024,
                'description': 'Tiny model (fast, basic responses)'
            },
            'small': {
                'temperature': 0.6,
                'max_tokens': 2048,
                'description': 'Small model (balanced speed/quality)'
            },
            'medium': {
                'temperature': 0.7,
                'max_tokens': 3072,
                'description': 'Medium model (good quality)'
            },
            'large': {
                'temperature': 0.5,
                'max_tokens': 4096,
                'description': 'Large model (high quality, slower)'
            },
            'xlarge': {
                'temperature': 0.3,
                'max_tokens': 4096,
                'description': 'Extra large model (best quality, slowest)'
            }
        }

        config = configs[detected_size]

        # Apply auto-configuration
        self.config.model.temperature = config['temperature']
        self.config.model.max_tokens = config['max_tokens']

        console.print(f"[blue]Auto-configured for {detected_size} model:[/blue]")
        console.print(f"  Temperature: {config['temperature']}")
        console.print(f"  Max tokens: {config['max_tokens']}")
        console.print(f"  Profile: {config['description']}")

        return detected_size, config

