    async def manage_setting(self, setting_path: str):
        """Manage specific setting based on path"""
        try:
            parts = setting_path.split()
            if len(parts) == 1:
                # Show category or specific setting
                await self.show_setting_category(parts[0])
            elif len(parts) == 2:
                # Set specific setting value
                setting_name, value = parts
                await self.set_setting_value(setting_name, value)
            else:
                console.print("[yellow]Usage: /settings <setting> [value][/yellow]")

        except Exception as e:
            console.print(f"[red]Error managing setting: {e}[/red]")

