    async def set_setting_value(self, setting_name: str, value: str):
        """Set a specific setting value"""
        try:
            # Parse boolean values
            if value.lower() in ['true', '1', 'yes', 'on']:
                bool_value = True
            elif value.lower() in ['false', '0', 'no', 'off']:
                bool_value = False
            else:
                bool_value = None

            # Handle model settings
            if setting_name == 'model.temperature':
                try:
                    temp_value = float(value)
                    if 0.0 <= temp_value <= 1.0:
                        self.config.model.temperature = temp_value
                        console.print(f"[green]Set temperature to {temp_value}[/green]")
                    else:
                        console.print("[red]Temperature must be between 0.0 and 1.0[/red]")
                except ValueError:
                    console.print("[red]Temperature must be a number[/red]")

            elif setting_name == 'model.max_tokens':
                try:
                    token_value = int(value)
                    if token_value > 0:
                        self.config.model.max_tokens = token_value
                        console.print(f"[green]Set max_tokens to {token_value}[/green]")
                    else:
                        console.print("[red]Max tokens must be positive[/red]")
                except ValueError:
                    console.print("[red]Max tokens must be a number[/red]")

            elif setting_name == 'model.auto-config':
                if bool_value is not None:
                    if bool_value:
                        size, config = self.auto_configure_model_by_size(self.config.model.name)
                        console.print("[green]Auto-configuration enabled and applied[/green]")
                    else:
                        console.print("[green]Auto-configuration disabled[/green]")
                else:
                    console.print("[red]Auto-config requires true/false value[/red]")

            # Handle interface settings
            elif setting_name == 'interface.compact_mode':
                if bool_value is not None:
                    self.config.interface.compact_mode = bool_value
                    console.print(f"[green]Set compact_mode to {bool_value}[/green]")
                else:
                    console.print("[red]Compact mode requires true/false value[/red]")

            elif setting_name == 'interface.syntax_highlighting':
                if bool_value is not None:
                    self.config.interface.syntax_highlighting = bool_value
                    console.print(f"[green]Set syntax_highlighting to {bool_value}[/green]")
                else:
                    console.print("[red]Syntax highlighting requires true/false value[/red]")

            elif setting_name == 'interface.auto_model_selection':
                if bool_value is not None:
                    if not hasattr(self.config.interface, 'auto_model_selection'):
                        self.config.interface.auto_model_selection = False
                    self.config.interface.auto_model_selection = bool_value
                    console.print(f"[green]Set auto_model_selection to {bool_value}[/green]")
                    console.print("[dim]Auto model selection controls whether MVCO recommendations are automatically applied[/dim]")
                else:
                    console.print("[red]Auto model selection requires true/false value[/red]")

            elif setting_name == 'interface.auto_suggest_tools':
                if bool_value is not None:
                    if not hasattr(self.config.interface, 'auto_suggest_tools'):
                        self.config.interface.auto_suggest_tools = False
                    self.config.interface.auto_suggest_tools = bool_value
                    console.print(f"[green]Set auto_suggest_tools to {bool_value}[/green]")
                    console.print("[dim]Suggest saving/running code blocks when strong indicators exist[/dim]")
                else:
                    console.print("[red]auto_suggest_tools requires true/false value[/red]")

            elif setting_name == 'interface.default_mode':
                val = value.strip().lower()
                if val in ['fast','auto','think','smart']:
                    self.config.interface.default_mode = val
                    self._current_mode = val
                    try:
                        if self.quality_manager:
                            self.quality_manager.set_quality_mode('fast' if val=='fast' else 'think' if val=='think' else 'auto')
                    except Exception:
                        pass
                    console.print(f"[green]Set default_mode to {val}[/green]")
                else:
                    console.print("[red]default_mode must be one of: fast, auto, think, smart[/red]")

            # Handle history settings
            elif setting_name == 'history.max_entries':
                try:
                    max_val = int(value)
                    if max_val > 0:
                        self.config.history.max_entries = max_val
                        console.print(f"[green]Set max_entries to {max_val}[/green]")
                    else:
                        console.print("[red]Max entries must be positive[/red]")
                except ValueError:
                    console.print("[red]Max entries must be a number[/red]")

            elif setting_name == 'history.save_to_file':
                if bool_value is not None:
                    self.config.history.save_to_file = bool_value
                    console.print(f"[green]Set save_to_file to {bool_value}[/green]")
                else:
                    console.print("[red]Save to file requires true/false value[/red]")

            elif setting_name == 'history.resume_last_session':
                if bool_value is not None:
                    self.config.history.resume_last_session = bool_value
                    console.print(f"[green]Set resume_last_session to {bool_value}[/green]")
                else:
                    console.print("[red]resume_last_session requires true/false value[/red]")

            # Handle tool commands
            elif setting_name == 'tools.enable':
                # Enable a specific tool
                if self.tool_manager.enable_tool(value):
                    console.print(f"[green]✓ Enabled tool: {value}[/green]")
                    console.print(f"[dim]Total enabled tools: {len(self.tool_manager.get_available_tools())}[/dim]")
                elif value not in self.tool_manager.get_all_tool_names():
                    console.print(f"[red]✗ Tool not found: {value}[/red]")
                    console.print(f"[dim]Available tools: {', '.join(self.tool_manager.get_all_tool_names())}[/dim]")
                else:
                    console.print(f"[yellow]Tool '{value}' is already enabled[/yellow]")

            elif setting_name == 'tools.disable':
                # Disable a specific tool
                if self.tool_manager.disable_tool(value):
                    console.print(f"[green]✓ Disabled tool: {value}[/green]")
                    console.print(f"[dim]Total enabled tools: {len(self.tool_manager.get_available_tools())}[/dim]")
                else:
                    console.print(f"[yellow]Tool '{value}' is not enabled[/yellow]")

            elif setting_name == 'tools.clear_cache':
                # Clear tool result cache
                self.tool_manager.clear_cache()
                console.print("[green]✓ Tool cache cleared[/green]")

            elif setting_name == 'tools.auto_retry':
                if bool_value is not None:
                    self.config.tools.auto_retry = bool_value
                    console.print(f"[green]Set auto_retry to {bool_value}[/green]")
                else:
                    console.print("[red]auto_retry requires true/false value[/red]")

            elif setting_name == 'tools.cache_results':
                if bool_value is not None:
                    self.config.tools.cache_results = bool_value
                    console.print(f"[green]Set cache_results to {bool_value}[/green]")
                else:
                    console.print("[red]cache_results requires true/false value[/red]")

            # Handle system commands
            elif setting_name == 'system.save':
                if self.config.config_path:
                    self.config.save(self.config.config_path)
                    console.print("[green]Configuration saved successfully[/green]")
                else:
                    console.print("[yellow]No config path set - cannot save[/yellow]")

            elif setting_name == 'system.reset':
                # Create operation info for confirmation gate
                operation = OperationInfo(
                    operation_name="Reset System Configuration",
                    description="Reset all configuration settings to defaults",
                    risk_level=RiskLevel.HIGH,
                    affected_items=[
                        "Model settings", "Interface settings", "History settings",
                        "Tools settings", "Runtime settings"
                    ],
                    consequences=[
                        "All custom configuration will be lost",
                        "Model selection will reset to default",
                        "Runtime profiles will reset to default",
                        "Tool permissions will reset",
                        "Application will restart with default settings"
                    ],
                    reversible=False,
                    backup_available=True,  # Config can be exported first
                    estimated_time="< 10 seconds"
                )

                # Require confirmation
                if not confirmation_gate.require_confirmation(operation):
                    console.print("[yellow]System reset cancelled[/yellow]")
                    return

                # Backup current config
                try:
                    backup_path = f"config_backup_{int(time.time())}.json"
                    self.config.save(backup_path)
                    console.print(f"[green]Configuration backed up to: {backup_path}[/green]")
                except Exception as e:
                    console.print(f"[yellow]Warning: Could not backup config: {e}[/yellow]")

                # Reset to defaults
                try:
                    self.config = Config()  # Create new default config
                    self.config.save()  # Save defaults
                    console.print("[green]✓ System configuration reset to defaults[/green]")
                    console.print("[yellow]Please restart the application for all changes to take effect[/yellow]")
                except Exception as e:
                    console.print(f"[red]Failed to reset configuration: {e}[/red]")

            # Handle runtime settings
            elif setting_name == 'runtime.resources':
                try:
                    resources_value = int(value)
                    if resources_value in [25, 50, 75, 100]:
                        self.config.runtime.resources = resources_value
                        console.print(f"[green]Set resources to {resources_value}%[/green]")
                        profile = resource_manager.get_profile_by_percentage(resources_value)
                        console.print(f"[dim]Profile: {profile.description}[/dim]")
                        # Update orchestrator with new resource settings
                        self._update_orchestrator_resources()
                    else:
                        console.print("[red]Resources must be one of: 25, 50, 75, 100[/red]")
                except ValueError:
                    console.print("[red]Resources must be a number[/red]")

            elif setting_name == 'runtime.auto_detect':
                if bool_value is not None:
                    self.config.runtime.auto_detect = bool_value
                    console.print(f"[green]Set auto_detect to {bool_value}[/green]")
                else:
                    console.print("[red]Auto detect requires true/false value[/red]")

            elif setting_name == 'runtime.gpu_enabled':
                if bool_value is not None:
                    self.config.runtime.gpu_enabled = bool_value
                    console.print(f"[green]Set gpu_enabled to {bool_value}[/green]")
                else:
                    console.print("[red]GPU enabled requires true/false value[/red]")

            elif setting_name == 'runtime.slice_generation':
                if bool_value is not None:
                    self.config.runtime.slice_generation = bool_value
                    console.print(f"[green]Set slice_generation to {bool_value}[/green]")
                else:
                    console.print("[red]Slice generation requires true/false value[/red]")

            elif setting_name == 'runtime.fallback_model':
                self.config.runtime.fallback_model = value
                console.print(f"[green]Set fallback_model to {value}[/green]")

            elif setting_name == 'runtime.cpu_threads':
                try:
                    threads_value = int(value)
                    if 1 <= threads_value <= 64:
                        self.config.runtime.cpu_threads = threads_value
                        console.print(f"[green]Set cpu_threads to {threads_value}[/green]")
                    else:
                        console.print("[red]CPU threads must be between 1 and 64[/red]")
                except ValueError:
                    console.print("[red]CPU threads must be a number[/red]")

            elif setting_name == 'runtime.max_memory_mb':
                try:
                    memory_value = int(value)
                    if 100 <= memory_value <= 1000000:
                        self.config.runtime.max_memory_mb = memory_value
                        console.print(f"[green]Set max_memory_mb to {memory_value}[/green]")
                    else:
                        console.print("[red]Memory must be between 100 and 1000000 MB[/red]")
                except ValueError:
                    console.print("[red]Memory must be a number[/red]")

            # Handle MCP settings
            elif setting_name == 'mcp.enabled':
                if bool_value is not None:
                    self.config.mcp.enabled = bool_value
                    console.print(f"[green]Set mcp.enabled to {bool_value}[/green]")
                    # If MCP is enabled/disabled, re-initialize
                    self._mcp_enabled = bool_value
                    if self._mcp_enabled:
                        console.print("[dim]Attempting to start MCP integration...[/dim]")
                        try:
                            self.mcp_integration = await integrate_mcp(self)
                            if self.mcp_integration:
                                console.print("[dim]✓ MCP integration active[/dim]")
                        except Exception as e:
                            console.print(f"[yellow]⚠ MCP initialization failed: {e}[/yellow]")
                    else:
                        console.print("[dim]Attempting to stop MCP integration...[/dim]")
                        if self.mcp_integration:
                            try:
                                await self.mcp_integration.stop()
                                self.mcp_integration = None
                                console.print("[dim]✓ MCP integration stopped[/dim]")
                            except Exception as e:
                                console.print(f"[dim]MCP cleanup error: {e}[/dim]")
                else:
                    console.print("[red]mcp.enabled requires true/false value[/red]")

            elif setting_name == 'mcp.auto_start':
                if bool_value is not None:
                    self.config.mcp.auto_start = bool_value
                    console.print(f"[green]Set mcp.auto_start to {bool_value}[/green]")
                else:
                    console.print("[red]mcp.auto_start requires true/false value[/red]")

            elif setting_name == 'mcp.mode':
                val = value.strip().lower()
                if val in ['embedded', 'client']:
                    self.config.mcp.mode = val
                    console.print(f"[green]Set mcp.mode to {val}[/green]")
                else:
                    console.print("[red]mcp.mode must be 'embedded' or 'client'[/red]")

            else:
                console.print(f"[yellow]Unknown setting: {setting_name}[/yellow]")
                return

            # Save configuration changes (except for system.save which handles its own saving)
            if not setting_name.startswith('system.') and self.config.config_path:
                self.config.save(self.config.config_path)
                console.print("[dim]Configuration saved[/dim]")

        except Exception as e:
            console.print(f"[red]Error setting value: {e}[/red]")
            console.print(f"[dim]Debug: {e.__class__.__name__}[/dim]")

    async def handle_versions_command(self, args: str):
        """Manage versioned overlays (non-destructive test/promote)."""
        if not self.version_manager:
            console.print("[yellow]Version manager not available in this build[/yellow]")
            return
        parts = (args or '').split()
        sub = parts[0] if parts else 'list'
        try:
            if sub == 'list':
                items = self.version_manager.list_overlays()
                if not items:
                    console.print("[yellow]No overlays found[/yellow]")
                    return
                console.print("[cyan]Overlays:[/cyan]")
                for it in items:
                    console.print(f"  • {it.get('id')} - {it.get('note','')}" )
            elif sub == 'preview' and len(parts) > 1:
                ov = self.version_manager.preview_overlay(parts[1])
                console.print(Markdown("```yaml\n" + yaml.safe_dump(ov, sort_keys=False) + "```"))
            elif sub == 'test' and len(parts) > 1:
                overlay_id = parts[1]
                def _recreate():
                    # Recreate router/policy to pick up new cfg
                    self.router = OpenCodeRouter(self.config)
                    provider_name = getattr(getattr(self.config, 'policy', None), 'provider', 'basic')
                    self.policy_provider = AdaptivePolicyProvider() if str(provider_name).lower() in ('advanced','adaptive') else BasicPolicyProvider()
                self.version_manager.test_overlay(overlay_id, self.config, _recreate)
                console.print(f"[green]Applied overlay {overlay_id} for testing[/green]")
            elif sub == 'end':
                def _recreate():
                    self.router = OpenCodeRouter(self.config)
                    provider_name = getattr(getattr(self.config, 'policy', None), 'provider', 'basic')
                    self.policy_provider = AdaptivePolicyProvider() if str(provider_name).lower() in ('advanced','adaptive') else BasicPolicyProvider()
                self.version_manager.end_test(self.config, _recreate)
                console.print("[green]Reverted to stable configuration[/green]")
                self._overlay_active_banner_shown = False
            elif sub == 'save':
                note = ' '.join(parts[1:]) if len(parts) > 1 else ''
                overlay_id = self.version_manager.save_current_as_overlay(self.config, note)
                console.print(f"[green]Saved current knobs as overlay {overlay_id}[/green]")
            elif sub == 'delete' and len(parts) > 1:
                self.version_manager.delete_overlay(parts[1])
                console.print(f"[yellow]Deleted overlay {parts[1]}[/yellow]")
            elif sub == 'promote' and len(parts) > 1:
                # Confirm promotion
                op = OperationInfo(
                    operation_name="Promote Overlay",
                    description=f"Merge overlay {parts[1]} into stable config",
                    risk_level=RiskLevel.MEDIUM,
                    affected_items=[self.config.config_path or 'config.yaml'],
                    consequences=["Stable config will be modified"],
                    reversible=True,
                    backup_available=True
                )
                if confirmation_gate.require_confirmation(op):
                    path = self.config.config_path or 'config.yaml'
                    self.version_manager.promote_overlay(parts[1], path)
                    console.print(f"[green]Promoted overlay {parts[1]} to stable config[/green]")
                else:
                    console.print("[yellow]Promotion cancelled[/yellow]")
            elif sub == 'metrics' and len(parts) > 1:
                path = Path('versions') / parts[1] / 'metrics.json'
                if path.exists():
                    console.print(Markdown("```json\n" + path.read_text() + "```"))
                else:
                    console.print("[yellow]No metrics found for overlay[/yellow]")
            else:
                console.print("[yellow]Usage: /versions list|preview <id>|test <id>|end|promote <id>|save [note]|delete <id>|metrics <id>[/yellow]")
        except Exception as e:
            console.print(f"[red]Error handling versions command: {e}[/red]")

    async def handle_mode_command(self, mode_args: str):
        """Handle /mode command for resource and generation mode setting"""
        try:
            if not mode_args:
                await self.show_mode_status()
                return

            parts = mode_args.split()
            mode_type = parts[0].lower()

            if mode_type == "fast":
                # Fast mode: minimal resources, quick responses
                self.config.runtime.resources = 25
                self._current_mode = 'fast'
                try:
                    self.config.interface.default_mode = 'fast'
                except Exception:
                    pass
                console.print("[green]🚀 Fast mode activated[/green]")
                console.print("[dim]• Resource usage: 25% (conservative)[/dim]")
                console.print("[dim]• Generation: Quick responses, minimal processing[/dim]")
                # Keep quality system in sync
                try:
                    if self.quality_manager:
                        self.quality_manager.set_quality_mode('fast')
                except Exception:
                    pass

            elif mode_type == "auto":
                # Auto mode: balanced resources with time limit
                self.config.runtime.resources = 50
                self._current_mode = 'auto'
                try:
                    self.config.interface.default_mode = 'auto'
                except Exception:
                    pass
                console.print("[green]⚡ Auto mode activated[/green]")
                console.print("[dim]• Resource usage: 50% (balanced)[/dim]")
                console.print("[dim]• Generation: Balanced quality/speed[/dim]")
                try:
                    if self.quality_manager:
                        self.quality_manager.set_quality_mode('auto')
                except Exception:
                    pass

            elif mode_type == "think":
                # Enhanced Think mode with verification and complexity analysis
                self.config.runtime.resources = 75
                self._current_mode = 'think'
                try:
                    self.config.interface.default_mode = 'think'
                except Exception:
                    pass
                console.print("[green]🧠 Think mode activated[/green]")
                console.print("[dim]• Resource usage: 75% (aggressive)[/dim]")
                console.print("[dim]• Generation: Higher quality, more time allowed[/dim]")
                console.print("[dim]• Self-verification: Research workflow protection enabled[/dim]")
                console.print("[dim]• Complexity analysis: Automatic resource optimization[/dim]")
                try:
                    if self.quality_manager:
                        self.quality_manager.set_quality_mode('think')
                except Exception:
                    pass

            elif mode_type == "smart":
                # Smart mode: complexity-based automatic resource allocation
                self._current_mode = 'smart'
                try:
                    self.config.interface.default_mode = 'smart'
                except Exception:
                    pass
                console.print("[green]🤖 Smart mode activated[/green]")
                console.print("[dim]• Automatic resource allocation based on input complexity[/dim]")
                console.print("[dim]• Range: 1-75% dynamically adjusted per query[/dim]")
                console.print("[dim]• Optimization: Context-aware performance tuning[/dim]")
                # Set a default but will be overridden per query
                self.config.runtime.resources = 50
                try:
                    if self.quality_manager:
                        self.quality_manager.set_quality_mode('auto')
                except Exception:
                    pass

            elif mode_type.isdigit():
                # Direct percentage mode (1-75%)
                percentage = int(mode_type)
                if 1 <= percentage <= 75:
                    self.config.runtime.resources = percentage
                    self._current_mode = f'custom_{percentage}'
                    console.print(f"[green]🎛️ Custom mode activated ({percentage}%)[/green]")
                    console.print(f"[dim]• Resource usage: {percentage}% (custom)[/dim]")
                    console.print(f"[dim]• Generation: Manual resource control[/dim]")

                    # Show resource details
                    try:
                        profile = resource_manager.get_profile_by_percentage(percentage)
                        console.print(f"[dim]• Context tokens: {profile.max_context_tokens:,}[/dim]")
                        console.print(f"[dim]• Threads: {profile.num_threads}[/dim]")

                        # Check feasibility
                        feasible, reason = resource_manager.is_profile_feasible(profile)
                        if not feasible:
                            console.print(f"[yellow]⚠️ {reason}[/yellow]")
                    except Exception as e:
                        console.print(f"[red]Error: {e}[/red]")
                        return
                else:
                    console.print(f"[red]Invalid percentage: {percentage}%. Must be between 1-75%[/red]")
                    return

            elif mode_type == "thinktime":
                # ThinkTime mode with specific soft time budget
                if len(parts) > 1:
                    # Support one or two time values: max [min]
                    raw_max = parts[1].strip().lower()
                    raw_min = parts[2].strip().lower() if len(parts) > 2 else None

                    def _parse_time(s: str) -> int | None:
                        try:
                            if s.endswith('s'):
                                return int(s[:-1])
                            if s.endswith('m'):
                                return int(s[:-1]) * 60
                            if s.endswith('h'):
                                return int(s[:-1]) * 3600
                            return int(s)
                        except Exception:
                            return None

                    secs_max = _parse_time(raw_max)
                    secs_min = _parse_time(raw_min) if raw_min else None

                    if secs_max is None or secs_max <= 0:
                        console.print("[red]Invalid time format. Use: /mode thinktime 60s or /mode thinktime 20m or /mode thinktime 60s 30s[/red]")
                        return

                    # Confirm applying thinktime budget
                    try:
                        op = OperationInfo(
                            operation_name="Set ThinkTime",
                            description=f"Apply thinktime (max={secs_max}s" + (f", min={secs_min}s" if secs_min else "") + ")",
                            risk_level=RiskLevel.LOW,
                            affected_items=[f"mode: think", f"max={secs_max}s"],
                            consequences=["Adjusts soft generation budgets"],
                            reversible=True,
                            backup_available=True,
                            estimated_time=f"~{secs_max}s"
                        )
                        if not confirmation_gate.require_confirmation(op):
                            console.print("[yellow]ThinkTime change cancelled[/yellow]")
                            return
                    except Exception:
                        pass

                    # Activate think with soft budgets
                    self.config.runtime.resources = 75
                    self._current_mode = 'think'
                    self._think_budget_max_secs = secs_max
                    self._think_budget_min_secs = secs_min if (secs_min and secs_min > 0) else None
                    # Ensure min <= max
                    if self._think_budget_min_secs and self._think_budget_min_secs > self._think_budget_max_secs:
                        self._think_budget_min_secs, self._think_budget_max_secs = self._think_budget_max_secs, self._think_budget_min_secs
                    # Do not persist default_mode for thinktime; ephemeral
                    # Friendly human-readable durations
                    def _fmt(secs: int) -> str:
                        if secs < 60:
                            return f"{secs}s"
                        mins = secs // 60
                        if mins < 60:
                            return f"{mins}m"
                        hrs = mins // 60
                        rem_m = mins % 60
                        return f"{hrs}h {rem_m}m" if rem_m else f"{hrs}h"
                    max_str = _fmt(self._think_budget_max_secs)
                    min_str = f", min {_fmt(self._think_budget_min_secs)}" if self._think_budget_min_secs else ""
                    console.print(f"[green]⏱️ ThinkTime mode activated (max {max_str}{min_str})[/green]")
                    console.print("[dim]• Resource usage: 75% (aggressive)[/dim]")
                    console.print(f"[dim]• Soft budgets: max={self._think_budget_max_secs}s{f', min={self._think_budget_min_secs}s' if self._think_budget_min_secs else ''}[/dim]")
                else:
                    console.print("[yellow]Usage: /mode thinktime <seconds>|<minutes>m|<hours>h[/yellow]")
                    console.print("[dim]Examples: /mode thinktime 60s  |  /mode thinktime 20m  |  /mode thinktime 60s 30s[/dim]")
                    return

            else:
                console.print(f"[red]Unknown mode: {mode_type}[/red]")
                console.print("[yellow]Available modes:[/yellow]")
                console.print("[dim]• fast - 25% resources (conservative)[/dim]")
                console.print("[dim]• auto - 50% resources (balanced)[/dim]")
                console.print("[dim]• think - 75% resources with verification[/dim]")
                console.print("[dim]• smart - Complexity-based automatic allocation[/dim]")
                console.print("[dim]• <1-75> - Custom percentage (e.g., /mode 30)[/dim]")
                console.print("[dim]• thinktime <N>m - Think mode with time limit[/dim]")
                return

            # Update orchestrator and save configuration
            self._update_orchestrator_resources()

            # Update Ollama client timeout based on resource level
            self._update_ollama_timeout_for_mode()
            # Show live resource profile
            try:
                profile = resource_manager.get_profile_by_percentage(self.config.runtime.resources)
                console.print(f"[dim]Resources now: threads={profile.num_threads}, ctx={profile.max_context_tokens} tokens[/dim]")
            except Exception:
                pass

            # Persist for stable modes only
            if mode_type != 'thinktime' and self.config.config_path:
                self.config.save(self.config.config_path)
                console.print("[dim]Mode saved to configuration[/dim]")

        except Exception as e:
            console.print(f"[red]Error setting mode: {e}[/red]")

