    async def handle_prompt_command(self, prompt_args: str):
        """Handle /prompt command"""
        try:
            args_lower = prompt_args.lower().strip()

            if args_lower == 'enable':
                self.system_prompt_enabled = True
                console.print("[green]✓ System prompt enabled (session only)[/green]")
            elif args_lower == 'enable save':
                self.system_prompt_enabled = True
                # Save to config by adding a system_prompt_enabled field
                if not hasattr(self.config, 'system_prompt_enabled'):
                    self.config.system_prompt_enabled = True
                else:
                    self.config.system_prompt_enabled = True
                if self.config.config_path:
                    self.config.save(self.config.config_path)
                    console.print("[green]✓ System prompt enabled and saved to config[/green]")
                else:
                    console.print("[yellow]✓ System prompt enabled (config path not available for saving)[/yellow]")
            elif args_lower == 'disable':
                self.system_prompt_enabled = False
                console.print("[yellow]⚠ System prompt disabled (session only)[/yellow]")
            elif args_lower == 'disable save':
                self.system_prompt_enabled = False
                # Save to config
                if not hasattr(self.config, 'system_prompt_enabled'):
                    self.config.system_prompt_enabled = False
                else:
                    self.config.system_prompt_enabled = False
                if self.config.config_path:
                    self.config.save(self.config.config_path)
                    console.print("[yellow]⚠ System prompt disabled and saved to config[/yellow]")
                else:
                    console.print("[yellow]⚠ System prompt disabled (config path not available for saving)[/yellow]")
            elif args_lower == 'reset':
                self.temp_system_prompt = None
                console.print("[green]✓ Temporary prompt cleared - using config default[/green]")
            elif args_lower == 'load':
                # Get active prompt
                active_prompt = self._get_dynamic_system_prompt(include_tools=False)
                if not active_prompt:
                    console.print("[red]No system prompt is currently active[/red]")
                    return

                # Display what we're loading
                console.print("[cyan]📥 Loading system prompt into model context...[/cyan]")
                prompt_source = "temporary custom prompt" if self.temp_system_prompt else "config.yaml"
                console.print(f"[dim]Source: {prompt_source} ({len(active_prompt)} chars)[/dim]")

                # Send to model as a system message to warm it up
                try:
                    client = self.get_active_client()
                    # Generate with just the prompt as input, model will acknowledge
                    response = await client.generate(
                        prompt="Acknowledge that you have received and understood the system prompt.",
                        system_prompt=active_prompt
                    )
                    console.print(f"[green]✓ System prompt loaded successfully[/green]")
                    if response:
                        console.print(f"[dim]Model response: {response[:200]}...[/dim]" if len(response) > 200 else f"[dim]Model response: {response}[/dim]")
                except Exception as e:
                    console.print(f"[red]Failed to load prompt: {e}[/red]")
            else:
                # Treat everything else as a custom prompt
                self.temp_system_prompt = prompt_args
                console.print(f"[green]✓ Temporary custom prompt set ({len(prompt_args)} chars)[/green]")
                console.print(f"[dim]This prompt will persist for this session only[/dim]")
                console.print(f"[dim]Preview: {prompt_args[:100]}...[/dim]")
        except Exception as e:
            console.print(f"[red]Error handling prompt command: {e}[/red]")

