                    console.print(f"  [dim]/tools prompt enable save[/dim] - Enable and save")
                    console.print(f"  [dim]/tools prompt disable[/dim] - Disable (session only)")
                    console.print(f"  [dim]/tools prompt disable save[/dim] - Disable and save")
