    async def handle_version_command(self, version_args: str):
        """Handle /version list|test <label>|save <label>|end."""
        try:
            if not VersionManager:
                console.print("[yellow]Version manager not available[/yellow]")
                return
            vm = self.version_manager or VersionManager(base_dir='versions')
            parts = (version_args or '').split()
            if not parts:
                parts = ['list']
            sub = parts[0].lower()
            # Prevent nested version launches inside a test session
            try:
                import os as _os
                in_test = _os.getenv('OPENCODE_TEST', '0').lower() in ('1', 'true')
            except Exception:
                in_test = False
            if in_test and sub not in ('list', 'save', 'end'):
                console.print("[yellow]Version switching disabled in test session. Use '/version save <label>' to set default or '/version end' to return to default.[/yellow]")
                return
            if sub == 'list':
                statuses = vm.list_versions_with_status()
                valid_entries = [it for it in statuses if it.get('complete') and it.get('valid')]
                if len(parts) > 1:
                    arg = parts[1]
                    if arg.isdigit():
                        i = int(arg)
                        if 1 <= i <= len(valid_entries):
                            label = valid_entries[i-1]['label']
                        else:
                            console.print("[red]Index out of range[/red]")
                            return
                    else:
                        label = arg
                        status = next((it for it in statuses if it['label'] == label), None)
                        if not status:
                            console.print(f"[red]Unknown version: {label}[/red]")
                            return
                        if not status.get('complete'):
                            console.print(f"[red]Version {label} is incomplete[/red]")
                            return
                        if not status.get('valid'):
                            console.print(f"[red]Version {label} failed validation. See versions/{label}/manifest.json[/red]")
                            return
                    try:
                        vm.set_active_test(label)
                    except Exception:
                        pass
                    console.print(f"[yellow]Starting version: {label}[/yellow]")
                    import subprocess
                    import os
                    from pathlib import Path as _P
                    # Use per-version Launcher if it exists, otherwise fall back to main Launcher
                    per_version_launcher = _P(f'versions/{label}/Launcher')
                    try:
                        self.session_manager.save_session_analytics()
                    except Exception:
                        pass
                    # Always use base Launcher with version parameter for reliability
                    launcher = str(_P('Launcher').resolve())
                    console.print(f"[cyan]DEBUG: About to execv: {launcher} --version {label} --test --no-prompt[/cyan]")
                    print(f"DEBUG: Current working directory: {os.getcwd()}")
                    print(f"DEBUG: Launcher exists: {_P('Launcher').exists()}")
                    print(f"DEBUG: Version dir exists: {_P(f'versions/{label}').exists()}")
                    os.execv(launcher, [launcher, '--version', label, '--test', '--no-prompt'])
                # Otherwise, print the list and prepare index map
                stable = vm.get_stable() or ''
                current = vm.get_current() or stable
                if not statuses:
                    console.print("[yellow]No versions found under ./versions[/yellow]")
                    return
                console.print("[cyan]Available versions:[/cyan]")
                index_map: List[str] = []
                idx = 1
                for status in statuses:
                    lb = status['label']
                    if status.get('complete') and status.get('valid'):
                        line = f"{idx}) {lb}"
                        index_map.append(lb)
                        idx += 1
                    else:
                        tag = 'incomplete' if not status.get('complete') else 'invalid'
                        line = f"- {lb} [{tag}]"
                    markers = []
                    if lb == stable:
                        markers.append("<STABLE>")
                    if lb == current:
                        markers.append("<CURRENT>")
                    suffix = " " + " ".join(markers) if markers else ""
                    console.print(f"  {line}{suffix}")
                self._version_index_map = index_map
                return
            elif (sub not in {'save','end','new'}) and len(parts) == 1:
                statuses = vm.list_versions_with_status()
                valid_entries = [it for it in statuses if it.get('complete') and it.get('valid')]
                arg = parts[0]
                if arg.isdigit():
                    i = int(arg)
                    if 1 <= i <= len(valid_entries):
                        label = valid_entries[i-1]['label']
                    else:
                        console.print("[red]Index out of range[/red]")
                        return
                else:
                    label = arg
                    status = next((it for it in statuses if it['label'] == label), None)
                    if not status:
                        console.print(f"[red]Unknown version: {label}[/red]")
                        return
                    if not status.get('complete'):
                        console.print(f"[red]Version {label} is incomplete[/red]")
                        return
                    if not status.get('valid'):
                        console.print(f"[red]Version {label} failed validation. See versions/{label}/manifest.json[/red]")
                        console.print(f"[cyan]DEBUG: status for {label}: {status}[/cyan]")
                        console.print(f"[cyan]DEBUG: status.get('valid'): {status.get('valid')}[/cyan]")
                        return
                try:
                    vm.set_active_test(label)
                except Exception:
                    pass
                console.print(f"[yellow]Starting version: {label}[/yellow]")
                import subprocess
                import os
                from pathlib import Path as _P
                # Use per-version Launcher if it exists, otherwise fall back to main Launcher
                per_version_launcher = _P(f'versions/{label}/Launcher')
                try:
                    self.session_manager.save_session_analytics()
                except Exception:
                    pass
                if per_version_launcher.exists():
                    launcher = str(per_version_launcher.resolve())
                    os.execv(launcher, [launcher, '--test', '--no-prompt'])
                else:
                    launcher = str(_P('Launcher').resolve())
                    os.execv(launcher, [launcher, '--version', label, '--test', '--no-prompt'])
            elif sub == 'save' and len(parts) > 1:
                label = parts[1]
                statuses = vm.list_versions_with_status()
                status = next((it for it in statuses if it['label'] == label), None)
                if not status:
                    console.print(f"[red]Unknown version: {label}[/red]")
                    return
                if not status.get('complete') or not status.get('valid'):
                    console.print(f"[red]Version {label} is not valid. See versions/{label}/manifest.json[/red]")
                    return
                vm.set_stable(label)
                console.print(f"[green]Saved stable version: {label}[/green]")
                console.print("[dim]Desktop launcher reads versions/STABLE; no manual repoint needed.[/dim]")
                return
            elif sub == 'end':
                # Clear active test and restart stable
                stable = vm.get_stable()
                vm.clear_active_test()
                if not stable:
                    console.print("[yellow]No stable pointer found. Nothing to switch to.[/yellow]")
                    return
                console.print(f"[yellow]Returning to stable version: {stable}[/yellow]")
                import subprocess
                import os
                from pathlib import Path as _P
                # Use per-version Launcher if it exists, otherwise fall back to main Launcher
                per_version_launcher = _P(f'versions/{stable}/Launcher')
                try:
                    self.session_manager.save_session_analytics()
                except Exception:
                    pass
                if per_version_launcher.exists():
                    launcher = str(per_version_launcher.resolve())
                    os.execv(launcher, [launcher, '--no-prompt'])
                else:
                    launcher = str(_P('Launcher').resolve())
                    os.execv(launcher, [launcher, '--version', stable, '--no-prompt'])
            elif sub == 'new':
                # /version new [label] [from=<label|stable|current>]
                new_label = None
                from_label = None
                if len(parts) > 1:
                    # parse key=value or label
                    for token in parts[1:]:
                        if token.startswith('from='):
                            from_label = token[5:]
                        elif new_label is None:
                            new_label = token
                try:
                    label, path = vm.create_version(new_label, from_label)
                    manifest_path = Path('versions') / label / 'manifest.json'
                    valid = False
                    errors: List[str] = []
                    if manifest_path.exists():
                        try:
                            with manifest_path.open('r') as mf:
                                data = json.load(mf)
                            valid = bool(data.get('valid', False))
                            errors = data.get('errors') or []
                        except Exception as e:
                            errors = [f"Could not read manifest: {e}"]
                    if valid:
                        console.print(f"[green]Created version '{label}' at {path}[/green]")
                    else:
                        console.print(f"[yellow]Created version '{label}', but validation warnings:")
                        for e in errors or ["Unknown error"]:
                            console.print(f"  - {e}")
                    console.print(f"[dim]Use '/version {label}' to run it, or '/version save {label}' to set stable.[/dim]")
                except Exception as e:
                    console.print(f"[red]Failed to create version: {e}")
                return
            else:
                console.print("[yellow]Usage: /version [list|<label>|<index>|save <label>|end|new [label] [from=...]][/yellow]")
        except SystemExit:
            raise
        except Exception as e:
            console.print(f"[red]Error handling version command: {e}[/red]")

    async def handle_project_command(self, project_args: str):
        """Handle /project command for project management"""
        try:
            if not project_args or project_args == "list":
                await self._project_list()
            elif project_args == "current":
                await self._project_current()
            elif project_args.startswith("new "):
                project_name = project_args[4:].strip()
                await self._project_new(project_name)
            elif project_args.startswith("select "):
                project_id = project_args[7:].strip()
                await self._project_select(project_id)
            elif project_args.startswith("export "):
                project_id = project_args[7:].strip()
                await self._project_export(project_id)
            elif project_args.startswith("archive "):
                project_id = project_args[8:].strip()
                await self._project_archive(project_id)
            elif project_args.startswith("info "):
                project_id = project_args[5:].strip()
                await self._project_info(project_id)
            else:
                console.print("[yellow]Usage: /project [list|new <name>|select <id>|current|export <id>|archive <id>|info <id>][/yellow]")

        except Exception as e:
            console.print(f"[red]Error managing project: {e}[/red]")

    async def _project_list(self):
        """List all projects"""
        projects = project_store.list_projects()
        current = project_store.get_current_project()

        if not projects:
            console.print("[yellow]No projects found[/yellow]")
            console.print("[dim]Use '/project new <name>' to create a project[/dim]")
            return

        console.print("[cyan]📁 Projects[/cyan]")
        for project in projects:
            current_indicator = " [green](current)[/green]" if current and project.id == current.id else ""
            archived_indicator = " [dim](archived)[/dim]" if 'archived' in project.tags else ""

            console.print(f"  {project.id}: {project.name}{current_indicator}{archived_indicator}")
            console.print(f"    [dim]{project.conversation_count} conversations, {project.total_tokens:,} tokens[/dim]")
            console.print(f"    [dim]Updated: {project.last_updated[:10]}[/dim]")

    async def _project_current(self):
        """Show current project info"""
        current = project_store.get_current_project()
        if current:
            console.print(f"[cyan]Current Project: {current.name}[/cyan]")
            console.print(f"ID: {current.id}")
            console.print(f"Description: {current.description or 'No description'}")
            console.print(f"Conversations: {current.conversation_count}")
            console.print(f"Tokens: {current.total_tokens:,}")
            console.print(f"Created: {current.created_at[:10]}")
            console.print(f"Updated: {current.last_updated[:10]}")
            if current.tags:
                console.print(f"Tags: {', '.join(current.tags)}")
        else:
            console.print("[yellow]No current project selected[/yellow]")
            console.print("[dim]Use '/project new <name>' to create a project[/dim]")

    async def _project_new(self, name: str):
        """Create a new project"""
        if not name:
            console.print("[red]Project name required[/red]")
            return

        project_id = project_store.create_project(name, f"Project created on {datetime.now().strftime('%Y-%m-%d')}")
        project_store.select_project(project_id)
        console.print(f"[green]✓ Created project: {name}[/green]")
        console.print(f"[dim]ID: {project_id} (now current)[/dim]")

    async def _project_select(self, project_id: str):
        """Select a project as current"""
        if project_store.select_project(project_id):
            project = project_store.get_current_project()
            console.print(f"[green]✓ Selected project: {project.name}[/green]")
            console.print(f"[dim]ID: {project_id}[/dim]")
        else:
            console.print(f"[red]Project not found: {project_id}[/red]")

    async def _project_export(self, project_id: str):
        """Export a project"""
        try:
            export_path = project_store.export_project(project_id)
            console.print(f"[green]✓ Project exported to: {export_path}[/green]")
        except ValueError as e:
            console.print(f"[red]{e}[/red]")

    async def _project_archive(self, project_id: str):
        """Archive a project"""
        if project_id not in project_store.projects:
            console.print(f"[red]Project not found: {project_id}[/red]")
            return

        project = project_store.projects[project_id]

        # Create operation info for confirmation gate
        operation = OperationInfo(
            operation_name="Archive Project",
            description=f"Archive project '{project.name}' ({project_id})",
            risk_level=RiskLevel.MEDIUM,
            affected_items=[f"Project: {project.name}", f"Conversations: {project.conversation_count}"],
            consequences=[
                "Project will be marked as archived",
                "Project will not appear in active lists",
                "Conversation data will be preserved",
                "Project can be restored later"
            ],
            reversible=True,
            backup_available=True,
            estimated_time="< 5 seconds"
        )

        # Require confirmation
        if not confirmation_gate.require_confirmation(operation):
            console.print("[yellow]Project archival cancelled[/yellow]")
            return

        if project_store.archive_project(project_id):
            console.print(f"[green]✓ Project {project_id} archived[/green]")
        else:
            console.print(f"[red]Failed to archive project: {project_id}[/red]")

    async def _project_info(self, project_id: str):
        """Show detailed project information"""
        if project_id not in project_store.projects:
            console.print(f"[red]Project not found: {project_id}[/red]")
            return

        project = project_store.projects[project_id]
        conversations = project_store.get_project_conversations(project_id, limit=5)

        console.print(f"[cyan]📁 {project.name}[/cyan]")
        console.print(f"ID: {project.id}")
        console.print(f"Description: {project.description or 'No description'}")
        console.print(f"Created: {project.created_at}")
        console.print(f"Last Updated: {project.last_updated}")
        console.print(f"Conversations: {project.conversation_count}")
        console.print(f"Total Tokens: {project.total_tokens:,}")
        if project.tags:
            console.print(f"Tags: {', '.join(project.tags)}")

        if conversations:
            console.print(f"\n[bold]Recent conversations (last {len(conversations)}):[/bold]")
            for conv in conversations[-5:]:
                role_indicator = "[USER]" if conv.role == "user" else "[AI]"
                preview = conv.content[:60] + "..." if len(conv.content) > 60 else conv.content
                console.print(f"  {role_indicator} {conv.timestamp[:16]}: {preview}")

        console.print(f"\n[dim]Project path: {project_store.get_project_path(project_id)}[/dim]")

    async def _generate_with_resources(self, prompt: str, system_prompt: str = None, task_type: str = 'standard', overrides: dict | None = None) -> str:
        """Generate text using resource-aware settings"""
        # Get current resource profile
        profile = resource_manager.get_profile_by_percentage(self.config.runtime.resources)

        # Create time budget based on mode
        if self.config.runtime.resources <= 25:
            # Fast mode: short budget
            budget = TimeBudget(total_seconds=15.0, started_at=time.time())
        elif self.config.runtime.resources <= 50:
            # Auto mode: moderate budget
            budget = TimeBudget(total_seconds=30.0, started_at=time.time())
        elif self.config.runtime.resources <= 75:
            # Think mode: generous budget
            budget = TimeBudget(total_seconds=60.0, started_at=time.time())
        else:
            # Maximum mode: very generous budget
            budget = TimeBudget(total_seconds=120.0, started_at=time.time())

        # Use time-sliced generation if enabled
        # Skip slicer in fast mode to reduce overhead
        if self.config.runtime.slice_generation and hasattr(self, 'time_slicer') and getattr(self, '_current_mode', 'auto') != 'fast':
            try:
                # Try time-sliced generation
                time_slicer = TimeSlicedGenerator(profile)
                return await time_slicer.generate_single_shot(
                    self.ollama_client, prompt, system_prompt, budget, task_type
                )
            except Exception as e:
                console.print(f"[dim yellow]Time-sliced generation failed, using standard: {e}[/dim yellow]")
                # Fall back to standard generation
                tools = getattr(self, '_current_tool_schemas', None)
                active_client = self.get_active_client()
                return await active_client.generate(prompt, system_prompt, task_type, tools=tools)
        else:
            # Standard generation with mode/policy-based caps and resource hints
            local_overrides = {}
            if overrides and isinstance(overrides, dict) and overrides:
                local_overrides = overrides
            else:
                # Fallback to mode-based overrides
                try:
                    local_overrides = self._compute_generation_overrides(task_type)
                except Exception:
                    local_overrides = {}

            # Streaming for fast/auto/smart and think with thinktime budgets
            try:
                mode_key = getattr(self, '_current_mode', 'auto')
                thinktime_active = bool(getattr(self, '_think_budget_max_secs', None) or getattr(self, '_think_budget_min_secs', None))
                if (mode_key in ('fast', 'auto', 'smart') and task_type in ('standard', 'structured', 'tool_use')) or (mode_key == 'think' and thinktime_active):
                    start_ts = time.time()
                    chunks: list[str] = []
                    self._token_counter = 0
                    self._start_time = start_ts

                    # Start keyboard listener for Ctrl+O thinking toggle
                    # self._start_keyboard_listener()  # DISABLED - potential issue
                    if self.history.debug_timing:
                        console.print(f"[dim]DEBUG: Starting streaming generation (mode={mode_key}, task={task_type})[/dim]")

                    try:
                        # Build streaming overrides similar to non-stream path
                        stream_overrides = dict(local_overrides)
                        options_override = stream_overrides.pop('options_override', None)
                        # Pass tool schemas if available
                        tools = getattr(self, '_current_tool_schemas', None)

                        # Stream without separate Live display (conflicts with Status spinner)
                        last_update = start_ts
                        last_printed_tokens = 0
                        if self.history.debug_timing:
                            console.print(f"[yellow]DEBUG: About to enter streaming loop...[/yellow]")

                        # Use active client (Ollama or llama.cpp)
                        active_client = self.get_active_client()
                        async for chunk in active_client.stream_generate(
                            prompt,
                            system_prompt,
                            task_type,
                            num_predict_override=stream_overrides.get('num_predict_override'),
                            temperature_override=stream_overrides.get('temperature_override'),
                            options_override=options_override,
                            tools=tools,
                        ):
                            chunks.append(chunk)
                            self._token_counter += 1

                            # Print chunk in real-time (apply thinking filter)
                            filtered_chunk = self._filter_thinking(chunk)

                            # Debug: show what's being filtered
                            if self.history.debug_timing and chunk != filtered_chunk:
                                console.print(f"\n[yellow]FILTERED: '{chunk}' -> '{filtered_chunk}'[/yellow]\n", end="")

                            if filtered_chunk:
                                console.print(filtered_chunk, end="")

                            # Print periodic updates (every 50 tokens to avoid spam)
                            now = time.time()
                            if self._token_counter - last_printed_tokens >= 50 and now - last_update >= 1.0:
                                elapsed = now - start_ts
                                # Calculate live context percentage
                                current_total_tokens = _estimate_tokens(prompt) + _estimate_tokens(system_prompt) + self._token_counter
                                max_context = self.config.model.max_tokens if hasattr(self.config.model, 'max_tokens') else 4096
                                live_context_percent = (current_total_tokens / max_context) * 100
                                console.print(f"[dim cyan]📊 {self._token_counter} tokens | ⏱️  {elapsed:.1f}s | 🧠 {live_context_percent:.0f}%[/dim cyan]")
                                last_update = now
                                last_printed_tokens = self._token_counter

                            # Respect soft max budget in thinktime
                            if mode_key == 'think' and thinktime_active:
                                max_secs = getattr(self, '_think_budget_max_secs', None)
                                if max_secs and (time.time() - start_ts) >= max_secs:
                                    break

                        # Final update
                        elapsed = time.time() - start_ts
                        console.print()  # Add newline after streaming output
                        console.print(f"[dim cyan]📊 Total: {self._token_counter} tokens | ⏱️  {elapsed:.1f}s[/dim cyan]")
                        if self.history.debug_timing:
                            console.print(f"[dim]DEBUG: Streaming completed successfully[/dim]")
                        combined = ''.join(chunks).strip()
                    finally:
                        # Always stop keyboard listener when done
                        self._stop_keyboard_listener_thread()
                    # Respect soft min budget in thinktime
                    if mode_key == 'think' and thinktime_active:
                        min_secs = getattr(self, '_think_budget_min_secs', None)
                        elapsed = time.time() - start_ts
                        if min_secs and elapsed < min_secs:
                            await asyncio.sleep(min_secs - elapsed)
                    if combined:
                        return combined
            except Exception as stream_err:
                # Fallback to non-streaming below
                console.print(f"[yellow]Streaming failed, falling back to non-streaming: {stream_err}[/yellow]")
                import traceback
                console.print(f"[dim]{traceback.format_exc()}[/dim]")

            # Pass tool schemas if available
            tools = getattr(self, '_current_tool_schemas', None)
            # Call active client (Ollama or llama.cpp) with proper parameters
            active_client = self.get_active_client()
            return await active_client.generate(
                prompt,
                system_prompt,
                task_type,
                tools=tools,
                num_predict_override=local_overrides.get('num_predict_override'),
                temperature_override=local_overrides.get('temperature_override'),
                options_override=local_overrides.get('options_override')
            )

    def _update_orchestrator_resources(self):
        """Update orchestrator resource settings when config changes"""
        if hasattr(self, 'tool_orchestrator') and self.tool_orchestrator:
            self.tool_orchestrator.update_resource_profile()

    def _update_ollama_timeout_for_mode(self):
        """Update Ollama client timeout based on current resource mode"""
        if not hasattr(self, 'ollama_client') or not self.ollama_client:
            return

        # No hard read timeouts: ensure client uses no read timeout
        try:
            import httpx
            if hasattr(self.ollama_client, 'client') and self.ollama_client.client:
                self.ollama_client.client.timeout = httpx.Timeout(None)
                console.print(f"[dim]All timeouts disabled for slow model loading[/dim]")
        except Exception as e:
            console.print(f"[yellow]Warning: Could not update client timeout: {e}[/yellow]")

    def _enforce_hyphen_bullets(self, text: str, n: int) -> str | None:
        """Normalize to hyphen bullets and trim to exactly n lines if possible.

        - Converts numbered or '*' bullets to '- '
        - Drops Markdown headings and empty lines
        - If fewer than n items remain, return original text
        """
        raw_lines = [ln.rstrip() for ln in text.splitlines()]
        norm: list[str] = []
        for ln in raw_lines:
            s = ln.strip()
            if not s:
                continue
            # Drop headings and section titles
            if s.startswith('#') or s.startswith('**') or s.endswith(':'):
                continue
            # Normalize numbered lists: '1. Item' or '1) Item'
            import re as _re
            if _re.match(r"^\d+[\.)]\s+", s):
                s = '- ' + _re.sub(r"^\d+[\.)]\s+", "", s)
            # Normalize star bullets
            if s.startswith('* '):
                s = '- ' + s[2:]
            # Keep only hyphen bullets
            if s.startswith('- '):
                norm.append(s)
        if not norm:
            return None
        if len(norm) >= n:
            return "\n".join(norm[:n])
        return None

    def _compute_generation_overrides(self, task_type: str) -> Dict[str, Optional[float]]:
        """Map /mode and task_type to generation limits and timeouts.

        Returns keys for OllamaClient.generate: num_predict_override,
        temperature_override, read_timeout_override.
        """
        mode = getattr(self, '_current_mode', 'auto') or 'auto'
        think_secs = getattr(self, '_think_budget_secs', None)

        # Defaults per mode (tuned for snappy structured lists in fast/auto)
        caps_fast = {'standard': 120, 'structured': 90, 'reasoning': 200}
        caps_auto = {'standard': 300, 'structured': 220, 'reasoning': 450}
        caps_think = {'standard': 600, 'structured': 350, 'reasoning': 900}

        if mode.startswith('fast'):
            cap = caps_fast.get(task_type, 256)
            read_to = None
        elif mode.startswith('think'):
            if think_secs:
                # Approximate tokens per second for small models
                tps = 10.0
                est = int(max(50, min(self.config.model.max_tokens, tps * float(think_secs))))
                if task_type == 'structured':
                    est = min(est, 400)
                cap = est
                read_to = float(think_secs)
            else:
                cap = caps_think.get(task_type, 800)
                read_to = None
        else:
            # auto / smart / custom_xx
            cap = caps_auto.get(task_type, 400)
            read_to = None

        temp = None
        if task_type == 'structured':
            # Lower temperature for tighter, less verbose lists
            temp = max(0.0, float(getattr(self.config.model, 'temperature', 0.7)) - 0.15)

        ov = {'num_predict_override': cap, 'temperature_override': temp}
        return ov

    async def handle_quality_command(self, command: str):
        """Handle quality system commands"""
        if not self.quality_manager:
            console.print("[yellow]Quality Recovery System is not available or disabled[/yellow]")
            return

        if command == 'status' or not command:
            try:
                status = self.quality_manager.get_quality_status()
                console.print(f"🎯 Quality System: [green]{status['system_health']}[/green]")

                quality_metrics = status.get('quality_system_status', {}).get('master_metrics', {})
                if quality_metrics:
                    instant_coverage = quality_metrics.get('instant_coverage_rate', 0)
                    avg_response_time = quality_metrics.get('average_response_time', 0)
                    console.print(f"📊 Instant Coverage: [cyan]{instant_coverage:.1%}[/cyan]")
                    console.print(f"⚡ Avg Response Time: [cyan]{avg_response_time:.3f}s[/cyan]")

                integration_metrics = status.get('integration_metrics', {})
                if integration_metrics:
                    total_requests = integration_metrics.get('total_requests', 0)
                    quality_used = integration_metrics.get('quality_system_used', 0)
                    fallback_used = integration_metrics.get('fallback_used', 0)
                    console.print(f"📈 Total Requests: {total_requests}")
                    console.print(f"✨ Quality System: {quality_used} | 🔄 Fallbacks: {fallback_used}")

            except Exception as e:
                console.print(f"[red]Error getting quality status: {e}[/red]")

        elif command.startswith('mode '):
            mode = command.split()[-1]
            try:
                self.quality_manager.set_quality_mode(mode)
                console.print(f"🔧 Quality mode set to: [green]{mode}[/green]")
            except ValueError as e:
                console.print(f"[red]Error: {e}[/red]")
                console.print("Available modes: fast, auto, think, learning")
            except Exception as e:
                console.print(f"[red]Error setting quality mode: {e}[/red]")

        elif command == 'optimize':
            try:
                result = self.quality_manager.optimize_quality_system()
                optimizations = result.get('optimizations_applied', [])
                console.print(f"🚀 Applied {len(optimizations)} optimizations:")
                for opt in optimizations[:5]:  # Show first 5
                    console.print(f"  • {opt}")
                if len(optimizations) > 5:
                    console.print(f"  ... and {len(optimizations) - 5} more")
            except Exception as e:
                console.print(f"[red]Error optimizing quality system: {e}[/red]")

        elif command == 'enable':
            try:
                self.quality_manager.enable_quality_system()
                console.print("[green]Quality system enabled[/green]")
            except Exception as e:
                console.print(f"[red]Error enabling quality system: {e}[/red]")

        elif command == 'disable':
            try:
                self.quality_manager.disable_quality_system()
                console.print("[yellow]Quality system disabled - using original processing[/yellow]")
            except Exception as e:
                console.print(f"[red]Error disabling quality system: {e}[/red]")

        else:
            console.print("[yellow]Available quality commands:[/yellow]")
            console.print("  /quality status    - Show quality system status")
            console.print("  /quality mode <mode> - Set quality mode (fast/auto/think/learning)")
            console.print("  /quality optimize  - Optimize quality system")
            console.print("  /quality enable    - Enable quality system")
            console.print("  /quality disable   - Disable quality system")

    async def handle_agentic_command(self, command: str):
        """Handle agentic project system commands"""
        # Import agentic system dynamically
        try:
            from .agentic_project_system import AgenticProjectManager
            if not hasattr(self, 'agentic_manager'):
                self.agentic_manager = AgenticProjectManager()
        except ImportError:
            console.print("[yellow]Agentic Project System is not available[/yellow]")
            return
        except Exception as e:
            console.print(f"[red]Error initializing agentic system: {e}[/red]")
            return

        if command == 'status' or not command:
            try:
                # Show agentic project status
                projects = self.agentic_manager.projects
                console.print(f"🤖 Agentic Projects: {len(projects)} active")

                if projects:
                    console.print("\n📋 Active Projects:")
                    for project_id, progress in projects.items():
                        phase = progress.current_phase.value if hasattr(progress, 'current_phase') else 'unknown'
                        console.print(f"  • {project_id}: [cyan]{phase}[/cyan]")
                else:
                    console.print("No active agentic projects")

            except Exception as e:
                console.print(f"[red]Error getting agentic status: {e}[/red]")

        elif command.startswith('create '):
            project_name = command[7:].strip()
            if not project_name:
                console.print("[red]Please provide a project name: /agentic create <project_name>[/red]")
                return

            try:
                # Create new agentic project
                project_id = f"project_{int(time.time())}"
                console.print(f"🚀 Creating agentic project: [cyan]{project_name}[/cyan]")
                console.print(f"📋 Project ID: {project_id}")
                console.print("[dim]Use /project commands to manage the project workflow[/dim]")
            except Exception as e:
                console.print(f"[red]Error creating agentic project: {e}[/red]")

        elif command == 'list':
            try:
                projects = self.agentic_manager.projects
                if projects:
                    console.print("📋 Agentic Projects:")
                    for project_id, progress in projects.items():
                        phase = progress.current_phase.value if hasattr(progress, 'current_phase') else 'unknown'
                        console.print(f"  {project_id}: {phase}")
                else:
                    console.print("No agentic projects found")
            except Exception as e:
                console.print(f"[red]Error listing projects: {e}[/red]")

        else:
            console.print("[yellow]Available agentic commands:[/yellow]")
            console.print("  /agentic status          - Show agentic system status")
            console.print("  /agentic create <name>   - Create new agentic project")
            console.print("  /agentic list            - List all agentic projects")
        
    async def handle_coding_command(self, args: str):
        """Handle /coding command for managing coding experiments."""
        parts = args.split()
        command = parts[0] if parts else "status"

        import os
        version = os.getenv('OPENCODE_VERSION', 'default')
        experiments_dir = Path('versions') / version / 'experiments'
        experiments_dir.mkdir(exist_ok=True)
        state_file = experiments_dir / '.state.json'

        def get_state():
            if state_file.exists():
                try:
                    return json.loads(state_file.read_text())
                except (json.JSONDecodeError, FileNotFoundError):
                    return {}
            return {}

        def save_state(state):
            try:
                tmp = state_file.with_suffix('.tmp')
                tmp.write_text(json.dumps(state, indent=2))
                tmp.replace(state_file)
            except Exception:
                state_file.write_text(json.dumps(state, indent=2))

        if command == "new":
            exp_name = parts[1] if len(parts) > 1 else f"exp_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            # Sanitize name
            try:
                import re as _re
                if not _re.match(r'^[A-Za-z0-9_-]+$', exp_name):
                    console.print("[red]Invalid experiment name. Use letters, numbers, '-', '_' only.[/red]")
                    return
            except Exception:
                pass
            exp_dir = experiments_dir / exp_name

            op_info = OperationInfo(
                operation_name="Create Coding Experiment",
                description=f"Create a new experiment sandbox: {exp_dir}",
                risk_level=RiskLevel.LOW,
                affected_items=[str(exp_dir)],
                consequences=["A new directory will be created."],
                reversible=True,
                backup_available=False
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Experiment creation cancelled.[/yellow]")
                return

            existed = exp_dir.exists()
            exp_dir.mkdir(exist_ok=True)
            (exp_dir / 'code').mkdir(exist_ok=True)
            (exp_dir / 'output').mkdir(exist_ok=True)
            (exp_dir / 'README.md').write_text(f"# Experiment: {exp_name}\n\nCreated: {datetime.now().isoformat()}")
            (exp_dir / 'code' / 'hello.txt').write_text("HI!")

            state = get_state()
            state['active_experiment'] = str(exp_dir)
            state['last_created'] = str(exp_dir)
            save_state(state)

            # Update tool working directory
            self.tool_manager.working_dir = exp_dir.resolve()

            if existed:
                console.print(f"[yellow]Using existing experiment: {exp_dir}[/yellow]")
            else:
                console.print(f"[green]✓ Created new experiment: {exp_dir}[/green]")
            console.print(f"[bold]Active experiment set to: {exp_name}[/bold]")
            console.print(f"[cyan]Tool working directory: {self.tool_manager.working_dir}[/cyan]")

        elif command in ["list", "ls"]:
            console.print(f"[bold]Experiments in version '{version}':[/bold]")
            state = get_state()
            active_exp = state.get('active_experiment')

            for exp in sorted(experiments_dir.iterdir()):
                if exp.is_dir() and not exp.name.startswith('.'):
                    marker = " (active)" if active_exp and Path(active_exp).name == exp.name else ""
                    console.print(f"- {exp.name}{marker}")

        elif command == "where":
            state = get_state()
            active_exp = state.get('active_experiment')
            if active_exp:
                console.print(f"Active experiment path: {active_exp}")
            else:
                console.print("[yellow]No active experiment.[/yellow]")

        elif command == "open":
            if len(parts) < 2:
                console.print("[red]Usage: /coding open <experiment_name>[/red]")
                return

            exp_name = parts[1]
            # Sanitize
            try:
                import re as _re
                if not _re.match(r'^[A-Za-z0-9_-]+$', exp_name):
                    console.print("[red]Invalid experiment name. Use letters, numbers, '-', '_' only.[/red]")
                    return
            except Exception:
                pass
            exp_dir = experiments_dir / exp_name
            if not exp_dir.is_dir():
                console.print(f"[red]Experiment '{exp_name}' not found.[/red]")
                return

            # Confirmation to switch active pointer
            op_info = OperationInfo(
                operation_name="Open Coding Experiment",
                description=f"Set active experiment to: {exp_name}",
                risk_level=RiskLevel.LOW,
                affected_items=[str(state_file)],
                consequences=["The active experiment pointer will be changed."],
                reversible=True,
                backup_available=False
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Operation cancelled.[/yellow]")
                return

            state = get_state()
            state['active_experiment'] = str(exp_dir)
            save_state(state)

            # Update tool manager working directory
            self.tool_manager.working_dir = exp_dir.resolve()

            console.print(f"[bold]Active experiment set to: {exp_name}[/bold]")
            console.print(f"[cyan]Tool working directory: {self.tool_manager.working_dir}[/cyan]")

        elif command == "gen":
            # /coding gen <file.py> <optional text>
            if len(parts) < 2:
                console.print("[red]Usage: /coding gen <file.py> [text][/red]")
                return
            target = parts[1]
            try:
                import re as _re
                if not _re.match(r'^[A-Za-z0-9_.-]+$', target):
                    console.print("[red]Invalid filename[/red]")
                    return
            except Exception:
                pass
            state = get_state()
            active_exp = state.get('active_experiment')
            if not active_exp:
                console.print("[yellow]No active experiment set. Use /coding new or /coding open first.[/yellow]")
                return
            exp_dir = Path(active_exp)
            code_dir = exp_dir / 'code'
            code_dir.mkdir(exist_ok=True)
            dest = code_dir / target
            content = " ".join(parts[2:]) if len(parts) > 2 else "# Auto-generated script\nprint('HI!')\n"
            # Confirm write
            op_info = OperationInfo(
                operation_name="Create Script",
                description=f"Create/overwrite {dest.name} in active experiment",
                risk_level=RiskLevel.MEDIUM,
                affected_items=[str(dest)],
                consequences=["File will be created or overwritten"],
                reversible=True,
                backup_available=True
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Operation cancelled.[/yellow]")
                return
            try:
                dest.write_text(content)
                console.print(f"[green]✓ Wrote {dest}[/green]")
                # Keep tools inside experiment
                self.tool_manager.working_dir = exp_dir.resolve()
            except Exception as e:
                console.print(f"[red]Write failed: {e}[/red]")
                return

        elif command == "run":
            # /coding run <file.py>
            if len(parts) < 2:
                console.print("[red]Usage: /coding run <file.py>[/red]")
                return
            target = parts[1]
            state = get_state()
            active_exp = state.get('active_experiment')
            if not active_exp:
                console.print("[yellow]No active experiment set. Use /coding new or /coding open first.[/yellow]")
                return
            exp_dir = Path(active_exp)
            code_path = exp_dir / 'code' / target
            if not code_path.exists():
                console.print(f"[red]Script not found: {code_path}[/red]")
                return
            # Confirm execution
            op_info = OperationInfo(
                operation_name="Run Script",
                description=f"Execute {target} in active experiment",
                risk_level=RiskLevel.LOW,
                affected_items=[str(code_path)],
                consequences=["Script will run and may write outputs"],
                reversible=True,
                backup_available=True
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Operation cancelled.[/yellow]")
                return
            try:
                # Use bash_execute tool with safe cwd and preferred interpreter
                interp = self._python_interpreter()
                result = await self.tool_manager.execute_tool(
                    'bash_execute',
                    command=f"{interp} {code_path.name}",
                    cwd=str((exp_dir / 'code').resolve())
                )
                if result.success:
                    console.print(f"[cyan]{result.output}\n[/cyan]" if result.output else "[green]✓ Script finished[/green]")
                else:
                    console.print(f"[red]Script failed: {result.error}[/red]")
            except Exception as e:
                console.print(f"[red]Execution error: {e}[/red]")
                return

        elif command == "status":
            state = get_state()
            active_exp = state.get('active_experiment')
            if active_exp:
                console.print(f"Active experiment: {Path(active_exp).name}")
            else:
                console.print("[yellow]No active experiment set.[/yellow]")
        else:
            console.print(f"[red]Unknown command: /coding {command}")
            console.print("Available commands: new, list, where, open, status")
